'use client';

import { signIn } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import { useState } from 'react';
import { InputField } from './components/InputField';

export default function RegisterPage(): React.JSX.Element {
  const router = useRouter();
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const onSubmit = async (event: React.FormEvent<HTMLFormElement>): Promise<void> => {
    event.preventDefault();
    setIsSubmitting(true);
    setError(null);

    const response = await fetch('/api/auth/register', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name: name.trim().length > 0 ? name.trim() : undefined, email, password }),
    });

    if (!response.ok) {
      setIsSubmitting(false);
      setError(response.status === 409 ? 'An account with this email already exists.' : 'Registration failed.');
      return;
    }

    const result = await signIn('credentials', {
      email,
      password,
      redirect: false,
      callbackUrl: '/admin/databases',
    });

    setIsSubmitting(false);
    if (result !== null && result.url !== undefined && result.url.length > 0) {
      router.push(result.url);
    } else {
      router.push('/admin/databases');
    }
    router.refresh();
  };

  const handleFormSubmit = (event: React.FormEvent<HTMLFormElement>): void => {
    void onSubmit(event);
  };

  return (
    <section className='mx-auto flex min-h-screen w-full max-w-md flex-col justify-center px-6 py-12'>
      <div className='space-y-6'>
        <div className='space-y-2'>
          <h1 className='text-2xl font-semibold tracking-normal text-foreground'>Create account</h1>
          <p className='text-sm text-muted-foreground'>Create a local Database Engine account.</p>
        </div>
        <form className='space-y-4' onSubmit={handleFormSubmit}>
          <InputField label='Name' type='text' autoComplete='name' value={name} onChange={setName} />
          <InputField label='Email' type='email' autoComplete='email' required value={email} onChange={setEmail} />
          <InputField label='Password' type='password' autoComplete='new-password' required minLength={8} value={password} onChange={setPassword} />
          {error !== null && error.length > 0 ? <p className='text-sm text-destructive'>{error}</p> : null}
          <button
            type='submit'
            disabled={isSubmitting}
            className='inline-flex h-10 w-full items-center justify-center rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:pointer-events-none disabled:opacity-60'
          >
            {isSubmitting ? 'Creating account...' : 'Create account'}
          </button>
        </form>
        <a className='text-sm font-medium text-primary hover:underline' href='/auth/signin'>
          Sign in instead
        </a>
      </div>
    </section>
  );
}

'use client';

import { signIn } from 'next-auth/react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useState } from 'react';

export default function SignInPage(): React.JSX.Element {
  const router = useRouter();
  const searchParams = useSearchParams();
  const callbackUrl = searchParams.get('callbackUrl') || '/admin/databases';
  const errorParam = searchParams.get('error');
  const denied = searchParams.get('denied') === '1';
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(
    denied ? 'You do not have permission to access Database Engine.' : errorParam ? 'Sign in failed.' : null
  );
  const [isSubmitting, setIsSubmitting] = useState(false);

  const onSubmit = async (event: React.FormEvent<HTMLFormElement>): Promise<void> => {
    event.preventDefault();
    setIsSubmitting(true);
    setError(null);

    const result = await signIn('credentials', {
      email,
      password,
      redirect: false,
      callbackUrl,
    });

    setIsSubmitting(false);
    if (result?.error) {
      setError('Invalid email or password.');
      return;
    }

    router.push(result?.url || callbackUrl);
    router.refresh();
  };

  return (
    <section className='mx-auto flex min-h-screen w-full max-w-md flex-col justify-center px-6 py-12'>
      <div className='space-y-6'>
        <div className='space-y-2'>
          <h1 className='text-2xl font-semibold tracking-normal text-foreground'>Database Engine</h1>
          <p className='text-sm text-muted-foreground'>Sign in with your local Database Engine account.</p>
        </div>
        <form className='space-y-4' onSubmit={onSubmit}>
          <label className='block space-y-2 text-sm font-medium text-foreground'>
            <span>Email</span>
            <input
              type='email'
              autoComplete='email'
              required
              value={email}
              onChange={(event) => setEmail(event.target.value)}
              className='h-10 w-full rounded-md border border-input bg-background px-3 text-sm outline-none ring-offset-background focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2'
            />
          </label>
          <label className='block space-y-2 text-sm font-medium text-foreground'>
            <span>Password</span>
            <input
              type='password'
              autoComplete='current-password'
              required
              value={password}
              onChange={(event) => setPassword(event.target.value)}
              className='h-10 w-full rounded-md border border-input bg-background px-3 text-sm outline-none ring-offset-background focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2'
            />
          </label>
          {error ? <p className='text-sm text-destructive'>{error}</p> : null}
          <button
            type='submit'
            disabled={isSubmitting}
            className='inline-flex h-10 w-full items-center justify-center rounded-md bg-primary px-4 text-sm font-medium text-primary-foreground transition-colors hover:bg-primary/90 disabled:pointer-events-none disabled:opacity-60'
          >
            {isSubmitting ? 'Signing in...' : 'Sign in'}
          </button>
        </form>
        <a className='text-sm font-medium text-primary hover:underline' href='/auth/register'>
          Create account
        </a>
      </div>
    </section>
  );
}

import 'server-only';

import type { AuthRole, AuthUserAccessDetail, AuthUserPageSettings, AuthUserRoleMap } from '@/shared/contracts/auth';
import type { MongoSettingRecord } from '@/shared/contracts/base';
import { authError } from '@/shared/errors/app-error';
import { AUTH_SETTINGS_KEYS } from '@/shared/lib/auth/constants';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { parseJsonSetting } from '@/shared/utils/settings-json';

const ROLE_ELEVATION_THRESHOLD = 90;
const AUTH_ACCESS_CACHE_TTL_MS = Number.parseInt(
  process.env['AUTH_ACCESS_CACHE_TTL_MS'] ?? process.env['AUTH_TOKEN_REFRESH_TTL_MS'] ?? '300000',
  10
);
const AUTH_SETTINGS_CACHE_TTL_MS = Number.parseInt(
  process.env['AUTH_SETTINGS_CACHE_TTL_MS'] ?? process.env['AUTH_ACCESS_CACHE_TTL_MS'] ?? '60000',
  10
);

const DEFAULT_AUTH_USER_PAGE_SETTINGS: AuthUserPageSettings = {
  allowSignup: true,
  allowPasswordReset: true,
  allowSocialLogin: true,
  requireEmailVerification: false,
};

const DEFAULT_AUTH_ROLES: AuthRole[] = [
  {
    id: 'super_admin',
    name: 'Super Admin',
    description: 'Full access to everything.',
    permissions: ['auth.users.read', 'auth.users.write', 'products.manage', 'notes.manage', 'chatbot.manage', 'ai_paths.manage', 'settings.manage', 'studiq.parent.access'],
    deniedPermissions: [],
    level: 100,
  },
  {
    id: 'superuser',
    name: 'Super User',
    description: 'Full access including system-level settings.',
    permissions: ['auth.users.read', 'auth.users.write', 'products.manage', 'notes.manage', 'chatbot.manage', 'ai_paths.manage', 'settings.manage', 'studiq.parent.access'],
    deniedPermissions: [],
    level: 95,
  },
  {
    id: 'admin',
    name: 'Admin',
    description: 'Full access to all apps and settings.',
    permissions: ['auth.users.read', 'auth.users.write', 'products.manage', 'notes.manage', 'chatbot.manage', 'ai_paths.manage', 'settings.manage', 'studiq.parent.access'],
    deniedPermissions: [],
    level: 90,
  },
  {
    id: 'viewer',
    name: 'Viewer',
    description: 'Read-only access.',
    permissions: ['auth.users.read'],
    deniedPermissions: [],
    level: 10,
  },
];

type MongoSettingDoc = Partial<MongoSettingRecord> & {
  updatedAt?: Date | string | null;
};

type AuthSettingsSnapshot = {
  roles: string | null;
  userRoles: string | null;
  defaultRole: string | null;
  userPages: string | null;
};

const parseCacheTtl = (value: number, fallback: number): number =>
  Number.isFinite(value) && value > 0 ? value : fallback;

const normalizeEmail = (email: string): string => email.trim().toLowerCase();

export const normalizeAuthEmail = normalizeEmail;

const getUpdatedAtMs = (value: Date | string | null | undefined): number | null => {
  if (value === null || value === undefined) return null;
  const parsed = value instanceof Date ? value.getTime() : Date.parse(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const pickPreferredSettingDoc = (docs: MongoSettingDoc[]): MongoSettingDoc | null => {
  let selected: MongoSettingDoc | null = null;
  for (const doc of docs) {
    if (doc === undefined || typeof doc.value !== 'string') continue;
    if (selected === null) {
      selected = doc;
      continue;
    }
    const docHasKey = typeof doc.key === 'string' && doc.key.trim().length > 0;
    const selectedHasKey = typeof selected.key === 'string' && selected.key.trim().length > 0;
    if (docHasKey && !selectedHasKey) {
      selected = doc;
      continue;
    }
    if (selectedHasKey && !docHasKey) continue;

    const docUpdated = getUpdatedAtMs(doc.updatedAt);
    const selectedUpdated = getUpdatedAtMs(selected.updatedAt);
    if (docUpdated !== null && (selectedUpdated === null || docUpdated > selectedUpdated)) {
      selected = doc;
    }
  }
  return selected;
};

const readMongoSettings = async (
  keys: readonly string[]
): Promise<Record<string, string | null>> => {
  if (!process.env['MONGODB_URI']) {
    return Object.fromEntries(keys.map((key) => [key, null]));
  }

  const mongo = await getMongoDb();
  const docs = await mongo
    .collection<MongoSettingDoc>('settings')
    .find(
      { $or: keys.flatMap((key) => [{ _id: key }, { key }]) },
      { projection: { _id: 1, key: 1, value: 1, updatedAt: 1 } }
    )
    .toArray();

  return Object.fromEntries(
    keys.map((key) => {
      const doc = pickPreferredSettingDoc(
        docs.filter((candidate) => candidate._id === key || candidate.key === key)
      );
      return [key, typeof doc?.value === 'string' ? doc.value : null];
    })
  );
};

let authSettingsSnapshotCache: { value: AuthSettingsSnapshot; ts: number } | null = null;
let authSettingsSnapshotInflight: Promise<AuthSettingsSnapshot> | null = null;

const getAuthSettingsSnapshot = async (): Promise<AuthSettingsSnapshot> => {
  const now = Date.now();
  const ttl = parseCacheTtl(AUTH_SETTINGS_CACHE_TTL_MS, 60_000);
  if (authSettingsSnapshotCache !== null && now - authSettingsSnapshotCache.ts < ttl) {
    return authSettingsSnapshotCache.value;
  }
  if (authSettingsSnapshotInflight !== null) return authSettingsSnapshotInflight;

  const promise = (async (): Promise<AuthSettingsSnapshot> => {
    const values = await readMongoSettings([
      AUTH_SETTINGS_KEYS.roles,
      AUTH_SETTINGS_KEYS.userRoles,
      AUTH_SETTINGS_KEYS.defaultRole,
      AUTH_SETTINGS_KEYS.userPages,
    ]);

    return {
      roles: values[AUTH_SETTINGS_KEYS.roles] ?? null,
      userRoles: values[AUTH_SETTINGS_KEYS.userRoles] ?? null,
      defaultRole: values[AUTH_SETTINGS_KEYS.defaultRole] ?? null,
      userPages: values[AUTH_SETTINGS_KEYS.userPages] ?? null,
    };
  })();

  authSettingsSnapshotInflight = promise;
  try {
    const value = await promise;
    authSettingsSnapshotCache = { value, ts: Date.now() };
    return value;
  } finally {
    authSettingsSnapshotInflight = null;
  }
};

const mergeDefaultRoles = (roles: AuthRole[] | null | undefined): AuthRole[] => {
  const incoming = Array.isArray(roles) ? roles : [];
  const defaults = new Map<string, AuthRole>(DEFAULT_AUTH_ROLES.map((role) => [role.id, role]));
  const merged = incoming.map((role) => {
    const fallback = defaults.get(role.id);
    if (!fallback) return role;
    return {
      ...fallback,
      ...role,
      permissions: Array.isArray(role.permissions) ? role.permissions : fallback.permissions,
      deniedPermissions: Array.isArray(role.deniedPermissions)
        ? role.deniedPermissions
        : fallback.deniedPermissions ?? [],
      level: typeof role.level === 'number' ? role.level : fallback.level,
    };
  });

  const known = new Set(merged.map((role) => role.id));
  for (const role of DEFAULT_AUTH_ROLES) {
    if (!known.has(role.id)) merged.push(role);
  }
  return merged;
};

const getAuthRoles = async (): Promise<AuthRole[]> => {
  const snapshot = await getAuthSettingsSnapshot();
  return mergeDefaultRoles(parseJsonSetting<AuthRole[]>(snapshot.roles, DEFAULT_AUTH_ROLES));
};

const getAuthUserRoles = async (): Promise<AuthUserRoleMap> => {
  const snapshot = await getAuthSettingsSnapshot();
  return parseJsonSetting<AuthUserRoleMap>(snapshot.userRoles, {});
};

const getAuthDefaultRoleId = async (): Promise<string | null> => {
  const snapshot = await getAuthSettingsSnapshot();
  return snapshot.defaultRole?.trim() || null;
};

export const getAuthUserPageSettings = async (): Promise<AuthUserPageSettings> => {
  const snapshot = await getAuthSettingsSnapshot();
  return parseJsonSetting<AuthUserPageSettings>(
    snapshot.userPages,
    DEFAULT_AUTH_USER_PAGE_SETTINGS
  );
};

const resolveEffectiveRole = (
  roleList: AuthRole[],
  userRoles: AuthUserRoleMap,
  userId: string,
  defaultRoleId: string | null
): { role: AuthRole; roleAssigned: boolean } => {
  const assignedRoleId = userRoles[userId];
  const assignedRole = roleList.find((role) => role.id === assignedRoleId);
  if (assignedRole) return { role: assignedRole, roleAssigned: true };

  const defaultRole =
    defaultRoleId !== null ? roleList.find((role) => role.id === defaultRoleId) : undefined;
  const fallbackRole =
    defaultRole ??
    roleList.find((role) => role.id === 'viewer') ??
    roleList[0] ??
    DEFAULT_AUTH_ROLES[0]!;

  return { role: fallbackRole, roleAssigned: false };
};

const accessCache = new Map<string, { value: AuthUserAccessDetail; ts: number }>();
const accessInflight = new Map<string, Promise<AuthUserAccessDetail>>();

export const invalidateAuthAccessCache = (userId?: string): void => {
  authSettingsSnapshotCache = null;
  authSettingsSnapshotInflight = null;
  if (userId !== undefined) {
    accessCache.delete(userId);
    accessInflight.delete(userId);
    return;
  }
  accessCache.clear();
  accessInflight.clear();
};

export const getAuthAccessForUser = async (userId: string): Promise<AuthUserAccessDetail> => {
  const now = Date.now();
  const ttl = parseCacheTtl(AUTH_ACCESS_CACHE_TTL_MS, 300_000);
  const cached = accessCache.get(userId);
  if (cached !== undefined && now - cached.ts < ttl) return cached.value;
  const inflight = accessInflight.get(userId);
  if (inflight !== undefined) return inflight;

  const promise = (async (): Promise<AuthUserAccessDetail> => {
    const [roles, userRoles, defaultRoleId] = await Promise.all([
      getAuthRoles(),
      getAuthUserRoles(),
      getAuthDefaultRoleId(),
    ]);
    const { role, roleAssigned } = resolveEffectiveRole(roles, userRoles, userId, defaultRoleId);
    const deniedPermissions = role.deniedPermissions ?? [];
    const permissions = (role.permissions ?? []).filter(
      (permission) => !deniedPermissions.includes(permission)
    );
    const level = role.level ?? 0;

    return {
      roleId: role.id,
      permissions,
      level,
      isElevated: level >= ROLE_ELEVATION_THRESHOLD,
      roleAssigned,
      role,
    };
  })();

  accessInflight.set(userId, promise);
  try {
    const value = await promise;
    accessCache.set(userId, { value, ts: Date.now() });
    return value;
  } finally {
    accessInflight.delete(userId);
  }
};

export async function readOptionalServerAuthSession() {
  const { auth } = await import('./auth');
  return auth();
}

export async function assertSettingsManageAccess(): Promise<void> {
  const session = await readOptionalServerAuthSession();
  const user = session?.user;
  if (user?.isElevated === true || user?.permissions?.includes('settings.manage')) return;

  throw authError('Unauthorized.');
}

import { hash } from 'bcryptjs';
import { type NextRequest, NextResponse } from 'next/server';

import { registerPayloadSchema, type RegisterPayload } from '@/shared/contracts/auth';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError, conflictError, forbiddenError } from '@/shared/errors/app-error';

import { getAuthUserPageSettings, normalizeAuthEmail } from '../../access';
import { createAuthUser, findAuthUserByEmail } from '../../user-repository';

export const registerSchema = registerPayloadSchema;

export async function postHandler(_req: NextRequest, ctx: ApiHandlerContext): Promise<Response> {
  const data = ctx.body as RegisterPayload | undefined;
  if (!data) throw badRequestError('Invalid payload');

  const pageSettings = await getAuthUserPageSettings();
  if (!pageSettings.allowSignup) {
    throw forbiddenError('Registration is disabled.');
  }

  if (!process.env['MONGODB_URI']) {
    throw badRequestError('MongoDB is not configured.');
  }

  const email = normalizeAuthEmail(data.email);
  const existing = await findAuthUserByEmail(email);
  if (existing) {
    throw conflictError('User already exists.', { email });
  }

  const passwordHash = await hash(data.password, 12);
  const user = await createAuthUser({
    email,
    name: data.name ?? null,
    passwordHash,
    emailVerified: data.emailVerified ?? false,
  });

  return NextResponse.json(
    { id: user.id, email: user.email, name: user.name },
    { status: 201 }
  );
}

import type { NextAuthConfig, Session, User } from 'next-auth';
import type { JWT } from 'next-auth/jwt';

const devFallbackSecret = 'dev-secret-change-me';
const secret =
  process.env['AUTH_SECRET'] ??
  process.env['NEXTAUTH_SECRET'] ??
  (process.env['NODE_ENV'] === 'development' ? devFallbackSecret : undefined);

const isProd = process.env['NODE_ENV'] === 'production';
const securePrefix = isProd ? '__Secure-' : '';
const hostPrefix = isProd ? '__Host-' : '';
const elevatedRoles = new Set(['admin', 'super_admin', 'superuser']);

type AuthUserInfo = {
  role?: string | null;
  isElevated?: boolean;
  accountDisabled?: boolean;
  accountBanned?: boolean;
  roleAssigned?: boolean;
  permissions?: string[];
};

type TokenData = {
  role?: string | null;
  permissions?: string[];
  roleLevel?: number | null;
  isElevated?: boolean;
  roleAssigned?: boolean;
  accountDisabled?: boolean;
  accountBanned?: boolean;
};

const isPlaywrightRuntime = Boolean(
  (process.env['PLAYWRIGHT_RUNTIME_LEASE_KEY'] ?? '') !== '' ||
    (process.env['PLAYWRIGHT_RUNTIME_AGENT_ID'] ?? '') !== ''
);

const isElevatedUser = (authUser: AuthUserInfo): boolean => {
  const role = authUser.role ?? 'unknown';
  return (authUser.isElevated ?? false) || elevatedRoles.has(role) || isPlaywrightRuntime;
};

const checkDatabaseAdminAccess = (
  pathname: string,
  authUser: AuthUserInfo
): boolean | { redirect: string; error?: string; denied?: boolean } => {
  if (authUser.accountBanned === true || authUser.accountDisabled === true) {
    return { redirect: '/auth/signin', error: 'AccountDisabled' };
  }

  const hasRoleAssigned = (authUser.roleAssigned ?? false) || isPlaywrightRuntime;
  if (!hasRoleAssigned && !isElevatedUser(authUser)) {
    return { redirect: '/auth/signin', error: 'AccessDenied' };
  }

  if (pathname.startsWith('/admin/databases')) {
    const permissions = authUser.permissions ?? [];
    if (!isElevatedUser(authUser) && !permissions.includes('settings.manage')) {
      return { redirect: '/admin', denied: true };
    }
  }

  return true;
};

const getUpdatedUser = (user: User, token: JWT): NonNullable<Session['user']> => {
  const t = token as TokenData;
  return {
    ...user,
    id: String(token.sub ?? user.id ?? ''),
    role: t.role ?? null,
    permissions: t.permissions ?? [],
    roleLevel: t.roleLevel ?? null,
    isElevated: t.isElevated ?? false,
    roleAssigned: t.roleAssigned ?? false,
    accountDisabled: t.accountDisabled ?? false,
    accountBanned: t.accountBanned ?? false,
  };
};

export const authConfig = {
  providers: [],
  pages: {
    signIn: '/auth/signin',
  },
  trustHost: true,
  ...(secret !== undefined ? { secret } : {}),
  cookies: {
    sessionToken: {
      name: `${securePrefix}authjs.session-token`,
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: isProd,
      },
    },
    callbackUrl: {
      name: `${securePrefix}authjs.callback-url`,
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: isProd,
      },
    },
    csrfToken: {
      name: `${hostPrefix}authjs.csrf-token`,
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: isProd,
      },
    },
    pkceCodeVerifier: {
      name: `${securePrefix}authjs.pkce.code_verifier`,
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: isProd,
      },
    },
    state: {
      name: `${securePrefix}authjs.state`,
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: isProd,
      },
    },
    nonce: {
      name: `${securePrefix}authjs.nonce`,
      options: {
        httpOnly: true,
        sameSite: 'lax',
        path: '/',
        secure: isProd,
      },
    },
  },
  session: { strategy: 'jwt' },
  callbacks: {
    authorized({
      auth,
      request: { nextUrl },
    }: {
      auth: Session | null;
      request: { nextUrl: URL };
    }): boolean | Response {
      const { pathname } = nextUrl;
      if (!pathname.startsWith('/admin')) return true;
      if (auth?.user === undefined) return false;

      const result = checkDatabaseAdminAccess(pathname, auth.user as AuthUserInfo);
      if (result === true) return true;
      if (result === false) return false;

      const redirectUrl = new URL(result.redirect, nextUrl);
      if (result.error !== undefined) redirectUrl.searchParams.set('error', result.error);
      if (result.denied === true) redirectUrl.searchParams.set('denied', '1');
      return Response.redirect(redirectUrl);
    },
    session({ session, token }: { session: Session; token: JWT }): Session {
      if (session.user === undefined) return session;
      return {
        ...session,
        user: getUpdatedUser(session.user, token),
      };
    },
  },
} satisfies NextAuthConfig;

import 'server-only';

import bcrypt from 'bcryptjs';
import NextAuth, { type NextAuthConfig, type Session, type User } from 'next-auth';
import Credentials from 'next-auth/providers/credentials';

import { ErrorSystem } from '@/shared/utils/observability/error-system';

import { authConfig } from './auth.config';
import { getAuthAccessForUser } from './access';
import { findAuthUserByEmail } from './user-repository';

import type { JWT } from 'next-auth/jwt';

type AuthCredentials = {
  email: string;
  password?: string;
};

const getString = (credentials: Record<string, unknown> | null, key: string): string | undefined => {
  const value = credentials?.[key];
  return typeof value === 'string' ? value : undefined;
};

const extractCredentials = (credentials: Record<string, unknown> | null): AuthCredentials => ({
  email: getString(credentials, 'email')?.trim().toLowerCase() ?? '',
  password: getString(credentials, 'password'),
});

const validateCredentials = async (credentials: AuthCredentials): Promise<User | null> => {
  if (credentials.email === '' || !credentials.password) return null;

  const user = await findAuthUserByEmail(credentials.email);
  if (!user?.passwordHash) return null;

  const passwordOk = await bcrypt.compare(credentials.password, user.passwordHash);
  if (!passwordOk) return null;

  const access = await getAuthAccessForUser(user.id);
  return {
    id: user.id,
    email: user.email,
    name: user.name,
    image: user.image,
    role: access.roleId,
    permissions: access.permissions,
    roleLevel: access.level,
    isElevated: access.isElevated,
    roleAssigned: access.roleAssigned,
    accountDisabled: false,
    accountBanned: false,
  };
};

const credentialsProvider = Credentials({
  name: 'Credentials',
  credentials: {},
  async authorize(credentials: Record<string, unknown> | null) {
    try {
      return await validateCredentials(extractCredentials(credentials));
    } catch (error) {
      await ErrorSystem.captureException(error, {
        service: 'database-engine.auth',
        action: 'authorize',
      });
      return null;
    }
  },
});

const shouldRefreshToken = (token: JWT): boolean => {
  const ttl = Number.parseInt(process.env['AUTH_TOKEN_REFRESH_TTL_MS'] ?? '300000', 10);
  const last = Number(token['authRefreshedAt'] ?? 0);
  if (typeof token.role !== 'string' || typeof token.roleAssigned !== 'boolean') return true;
  return Date.now() - last > (Number.isFinite(ttl) && ttl > 0 ? ttl : 300_000);
};

const refreshAccessToken = async (userId: string, token: JWT): Promise<JWT> => {
  const access = await getAuthAccessForUser(userId);
  return {
    ...token,
    role: access.roleId,
    permissions: access.permissions,
    roleLevel: access.level,
    isElevated: access.isElevated,
    roleAssigned: access.roleAssigned,
    accountDisabled: false,
    accountBanned: false,
    authRefreshedAt: Date.now(),
  };
};

const getSessionUser = (token: JWT, current: User): NonNullable<Session['user']> => ({
  ...current,
  id: String(token.sub ?? current.id ?? ''),
  role: token.role ?? null,
  permissions: token.permissions ?? [],
  roleLevel: token.roleLevel ?? null,
  isElevated: token.isElevated ?? false,
  roleAssigned: Boolean(token['roleAssigned'] ?? false),
  accountDisabled: token.accountDisabled ?? false,
  accountBanned: token.accountBanned ?? false,
});

const buildAuthConfig = (): NextAuthConfig => ({
  ...authConfig,
  providers: [credentialsProvider],
  callbacks: {
    ...authConfig.callbacks,
    async jwt({ token, user }): Promise<JWT> {
      const userId = user?.id ?? token.sub;
      if (userId === undefined || userId === '') return token;
      if (user === undefined && !shouldRefreshToken(token)) return token;
      try {
        return await refreshAccessToken(userId, token);
      } catch (error) {
        await ErrorSystem.captureException(error, {
          service: 'database-engine.auth',
          action: 'jwt_callback',
          userId,
        });
        return token;
      }
    },
    session({ session, token }): Session {
      return {
        ...session,
        user: getSessionUser(token, session.user),
      };
    },
  },
  debug: process.env['AUTH_DEBUG'] === 'true',
});

export const { handlers, auth, signIn, signOut } = NextAuth(buildAuthConfig());

import 'server-only';

import { ObjectId } from 'mongodb';

import { getMongoDb } from '@/shared/lib/db/mongo-client';

import { normalizeAuthEmail } from './access';

type MongoUserDoc = {
  _id?: ObjectId;
  email: string;
  name?: string | null;
  image?: string | null;
  passwordHash?: string | null;
  emailVerified?: Date | boolean | null;
  createdAt?: Date;
  updatedAt?: Date;
};

export type AuthUserRecord = {
  id: string;
  email: string;
  name: string | null;
  image: string | null;
  passwordHash: string | null;
  emailVerified: boolean | null;
};

const toRecord = (doc: MongoUserDoc & { _id: ObjectId }): AuthUserRecord => ({
  id: doc._id.toString(),
  email: doc.email,
  name: doc.name ?? null,
  image: doc.image ?? null,
  passwordHash: doc.passwordHash ?? null,
  emailVerified:
    typeof doc.emailVerified === 'boolean'
      ? doc.emailVerified
      : doc.emailVerified instanceof Date
        ? true
        : null,
});

export const findAuthUserByEmail = async (email: string): Promise<AuthUserRecord | null> => {
  const db = await getMongoDb();
  const normalized = normalizeAuthEmail(email);
  const doc = await db.collection<MongoUserDoc>('users').findOne({ email: normalized });
  if (!doc?._id) return null;
  return toRecord(doc as MongoUserDoc & { _id: ObjectId });
};

export const createAuthUser = async (input: {
  email: string;
  name?: string | null;
  passwordHash: string;
  emailVerified?: boolean;
}): Promise<AuthUserRecord> => {
  const db = await getMongoDb();
  const now = new Date();
  const doc: MongoUserDoc = {
    email: normalizeAuthEmail(input.email),
    name: input.name ?? null,
    image: null,
    passwordHash: input.passwordHash,
    emailVerified: input.emailVerified ? now : null,
    createdAt: now,
    updatedAt: now,
  };
  const result = await db.collection<MongoUserDoc>('users').insertOne(doc);
  return {
    id: result.insertedId.toString(),
    email: doc.email,
    name: doc.name ?? null,
    image: null,
    passwordHash: doc.passwordHash ?? null,
    emailVerified: input.emailVerified ? true : null,
  };
};

/**
 * Database Access Control
 * 
 * Server-side authorization checks for database operations.
 * 
 * Provides two access patterns:
 * 1. Standard admin access - requires settings.manage permission
 * 2. AI Paths internal access - allows AI workflows to access specific collections
 * 
 * This dual-access pattern enables:
 * - Secure admin database management interface
 * - Automated AI Path workflows that need database access
 * - Collection-level access restrictions for internal requests
 */

import 'server-only';

import type { NextRequest } from 'next/server';

import { forbiddenError } from '@/shared/errors/app-error';

import { assertSettingsManageAccess } from '../../auth/server';

const DEV_INTERNAL_HEADER_VALUE = 'dev-internal-header-value-change-me';

const DEFAULT_COLLECTION_ALLOWLIST = [
  'products',
  'product_drafts',
  'product_categories',
  'product_parameters',
  'product_category_assignments',
  'product_tags',
  'product_tag_assignments',
  'catalogs',
  'image_files',
  'product_listings',
  'product_ai_jobs',
  'product_producer_assignments',
  'filemaker_cvs',
  'filemaker_job_applications',
  'integrations',
  'integration_connections',
  'settings',
  'users',
  'user_preferences',
  'languages',
  'system_logs',
  'notes',
  'tags',
  'categories',
  'notebooks',
  'noteFiles',
  'themes',
  'chatbot_sessions',
  'auth_security_attempts',
  'auth_security_profiles',
  'auth_login_challenges',
];

type AllowlistConfig = {
  allowAll: boolean;
  allowed: Set<string>;
};

const normalizeCollectionName = (value: string): string => value.trim().toLowerCase();

const parseAllowlist = (raw: string): string[] =>
  raw
    .split(/[,\\n]/)
    .map((value) => value.trim())
    .filter(Boolean);

const buildAllowlist = (): AllowlistConfig => {
  const raw = process.env['AI_PATHS_DB_COLLECTION_ALLOWLIST'];
  if (raw === undefined || raw.trim().length === 0) {
    return {
      allowAll: false,
      allowed: new Set(DEFAULT_COLLECTION_ALLOWLIST.map(normalizeCollectionName)),
    };
  }

  const tokens = parseAllowlist(raw);
  const lowered = tokens.map(normalizeCollectionName);
  const allowAll = lowered.includes('*') || lowered.includes('all');
  const includeDefault = lowered.includes('default');
  const allowed = new Set<string>();

  if (includeDefault) {
    DEFAULT_COLLECTION_ALLOWLIST.forEach((collection) => {
      allowed.add(normalizeCollectionName(collection));
    });
  }

  tokens.forEach((token) => {
    const normalized = normalizeCollectionName(token);
    if (normalized === '*' || normalized === 'all' || normalized === 'default') return;
    allowed.add(normalized);
  });

  if (!allowAll && allowed.size === 0) {
    DEFAULT_COLLECTION_ALLOWLIST.forEach((collection) => {
      allowed.add(normalizeCollectionName(collection));
    });
  }

  return { allowAll, allowed };
};

const allowlistConfig = buildAllowlist();

const getExpectedInternalHeaderValue = (): string | null => {
  if (process.env['AI_PATHS_INTERNAL_TOKEN']) return process.env['AI_PATHS_INTERNAL_TOKEN'];
  if (process.env['AUTH_SECRET']) return process.env['AUTH_SECRET'];
  if (process.env['NEXTAUTH_SECRET']) return process.env['NEXTAUTH_SECRET'];
  if (process.env['NODE_ENV'] === 'development') return DEV_INTERNAL_HEADER_VALUE;
  return null;
};

export const isCollectionAllowed = (collection: string): boolean => {
  if (collection.trim().length === 0) return false;
  if (allowlistConfig.allowAll) return true;
  return allowlistConfig.allowed.has(normalizeCollectionName(collection));
};

export const getCollectionAllowlist = (): string[] => {
  if (allowlistConfig.allowAll) return ['*'];
  return Array.from(allowlistConfig.allowed).sort((a, b) => a.localeCompare(b));
};

export const isDatabaseEngineInternalRequest = (request: NextRequest): boolean => {
  const expectedHeaderValue = getExpectedInternalHeaderValue();
  if (!expectedHeaderValue) return false;
  const header = request.headers.get('x-ai-paths-internal');
  return Boolean(header && header === expectedHeaderValue);
};

/**
 * Assert user has database engine management access
 * Requires settings.manage permission
 */
export async function assertDatabaseEngineManageAccess(): Promise<void> {
  await assertSettingsManageAccess();
}

/**
 * Assert access for database operations with AI Paths internal bypass
 * 
 * Allows two access paths:
 * 1. AI Paths internal requests (with collection restrictions)
 * 2. Standard admin access (full access)
 * 
 * @param request - Next.js request object
 * @param options - Optional collection name for validation
 * @returns Object indicating if request is internal
 */
export async function assertDatabaseEngineManageAccessOrAiPathsInternal(
  request: NextRequest,
  options?: { collection?: string | null }
): Promise<{ isInternal: boolean }> {
  // Check if this is an AI Paths internal request
  if (isDatabaseEngineInternalRequest(request)) {
    const collection = options?.collection?.trim() ?? '';
    // Validate collection is in allowed list
    if (collection !== '' && isCollectionAllowed(collection) === false) {
      throw forbiddenError('Forbidden.');
    }
    return { isInternal: true };
  }

  // Fall back to standard admin access check
  await assertDatabaseEngineManageAccess();
  return { isInternal: false };
}

import {
  type DatabasePreviewGroup,
  type DatabasePreviewPayload,
  type DatabasePreviewRequest,
  type DatabasePreviewTable,
  type DatabaseTableDetail,
  type DatabaseTablePreviewData,
} from '@/shared/contracts/database';
import { type ApiPayloadResult } from '@/shared/contracts/http';
import { api, ApiError } from '@/shared/lib/api-client';
import { logClientError } from '@/shared/utils/observability/client-error-logger';
import { toFallbackErrorPayload } from './shared';

export const getDatabasePreview = async (
  input: DatabasePreviewRequest
): Promise<ApiPayloadResult<DatabasePreviewPayload>> => {
  try {
    const raw = await api.post<Record<string, unknown>>('/api/databases/preview', input);

    // Normalize response
    const normalizeGroups = (data: unknown): DatabasePreviewGroup[] => {
      if (!Array.isArray(data)) return [];
      return data.map((g: Record<string, unknown>) => ({
        type: (g['type'] ?? g['name']) as string,
        objects: Array.isArray(g['objects'])
          ? (g['objects'] as string[])
          : Array.isArray(g['tables'])
            ? (g['tables'] as string[])
            : [],
      }));
    };

    const rawStats = raw['stats'] as Record<string, unknown> | undefined;
    const groups = normalizeGroups(raw['groups'] ?? rawStats?.['groups']);
    const tables = (raw['tables'] ?? rawStats?.['tables'] ?? []) as DatabasePreviewTable[];
    const tableRows = (raw['tableRows'] ?? raw['data'] ?? []) as DatabaseTablePreviewData[];
    const tableDetails = (raw['tableDetails'] ?? []) as DatabaseTableDetail[];
    const finalPage = raw['page'] ?? input.page;
    const finalPageSize = raw['pageSize'] ?? input.pageSize;
    const databaseSize = (raw['databaseSize'] ?? rawStats?.['databaseSize'] ?? '') as string;

    const payload: DatabasePreviewPayload = {
      groups,
      tables,
      tableRows,
      tableDetails,
      databaseSize,
      total: (raw['total'] ?? rawStats?.['total'] ?? 0) as number,
      page: typeof finalPage === 'string' ? parseInt(finalPage, 10) : (finalPage as number) || 1,
      pageSize:
        typeof finalPageSize === 'string'
          ? parseInt(finalPageSize, 10)
          : (finalPageSize as number) || 50,
    };

    return { ok: true, payload };
  } catch (error) {
    logClientError(error);
    if (error instanceof ApiError) {
      if (error.payload !== undefined && error.payload !== null) {
        return { ok: false, payload: error.payload as DatabasePreviewPayload };
      }
      return { ok: false, payload: toFallbackErrorPayload<DatabasePreviewPayload>(error) };
    }
    return { ok: false, payload: toFallbackErrorPayload<DatabasePreviewPayload>(error) };
  }
};

export const fetchDatabasePreview = getDatabasePreview;

