export function DatabaseTableSelector(): React.JSX.Element {
  const { selectedTable, tableDetails, isFetching } = useCrudPanelStateContext();
  const { setSelectedTable, onRefresh, onAddRow, setPage, setMutationError, setSuccessMessage } =
    useCrudPanelActionsContext();
  const tableOptions = useMemo<Array<LabeledOptionDto<string>>>(
    () =>
      tableDetails.map((table) => ({
        value: table.name,
        label: `${table.name} (${table.rowEstimate.toLocaleString()} rows${
          table.sizeFormatted ? `, ${table.sizeFormatted}` : ''
        })`,
      })),
    [tableDetails]
  );
  return (
    <div className='flex flex-wrap items-center gap-3'>
      <SearchableSelect
        value={selectedTable}
        onChange={(v) => {
          setSelectedTable(v ?? '');
          setPage(1);
          setMutationError(null);
          setSuccessMessage(null);
        }}
        options={tableOptions}
        placeholder='Select a table to manage...'
        className='min-w-[280px]'
      />

      {selectedTable && (
        <>
          <div className='h-4 w-px bg-border/60 mx-1' />
          <Button
            variant='outline'
            size='xs'
            onClick={onRefresh}
            disabled={isFetching}
            className='h-8'
            loading={isFetching}
          >
            Refresh
          </Button>
          <Button size='xs' onClick={onAddRow} className='h-8'>
            <PlusIcon className='size-3.5 mr-2' />
            Add Row
          </Button>
        </>
      )}
    </div>
  );
}

'use client';

import {
  ChevronDownIcon,
  ChevronRightIcon,
  Columns3Icon,
  DatabaseIcon,
  HardDriveIcon,
  KeyRoundIcon,
  SearchIcon,
  Table2Icon,
} from 'lucide-react';
import type { JSX } from 'react';
import { useCallback, useEffect, useMemo, useState } from 'react';

import type { DatabaseTableDetail } from '@/shared/contracts/database';
import { Card } from '@/shared/ui/primitives.public';
import { cn } from '@/shared/utils/ui-utils';

const formatRows = (rows: number): string =>
  `${rows.toLocaleString()} ${rows === 1 ? 'row' : 'rows'}`;

const getSizeLabel = (sizeFormatted: string | undefined): string => {
  const trimmed = sizeFormatted?.trim();
  return trimmed && trimmed.length > 0 ? trimmed : 'n/a';
};

const matchesQuery = (value: string, query: string): boolean =>
  value.toLowerCase().includes(query);

export interface DatabaseTreePanelProps {
  databaseLabel: string;
  databaseSize: string;
  isFetching: boolean;
  onSelectTable: (tableName: string) => void;
  selectedTable: string;
  tableDetails: DatabaseTableDetail[];
}

export function DatabaseTreePanel({
  databaseLabel,
  databaseSize,
  isFetching,
  onSelectTable,
  selectedTable,
  tableDetails,
}: DatabaseTreePanelProps): JSX.Element {
  const [expandedTables, setExpandedTables] = useState<ReadonlySet<string>>(
    () => new Set(selectedTable !== '' ? [selectedTable] : [])
  );
  const [treeFilter, setTreeFilter] = useState('');
  const totalRows = tableDetails.reduce((sum, table) => sum + table.rowEstimate, 0);
  const databaseSizeLabel = getSizeLabel(databaseSize);
  const normalizedFilter = treeFilter.trim().toLowerCase();
  const filteredTableDetails = useMemo(() => {
    if (normalizedFilter === '') return tableDetails;
    return tableDetails.filter((table) => {
      if (matchesQuery(table.name, normalizedFilter)) return true;
      if (table.columns.some((column) => matchesQuery(column.name, normalizedFilter))) return true;
      return table.indexes.some((index) => matchesQuery(index.name, normalizedFilter));
    });
  }, [normalizedFilter, tableDetails]);

  useEffect(() => {
    if (selectedTable === '') return;
    setExpandedTables((current) => {
      if (current.has(selectedTable)) return current;
      const next = new Set(current);
      next.add(selectedTable);
      return next;
    });
  }, [selectedTable]);

  const toggleTable = useCallback((tableName: string) => {
    setExpandedTables((current) => {
      const next = new Set(current);
      if (next.has(tableName)) {
        next.delete(tableName);
      } else {
        next.add(tableName);
      }
      return next;
    });
  }, []);

  const expandVisibleTables = useCallback(() => {
    setExpandedTables(new Set(filteredTableDetails.map((table) => table.name)));
  }, [filteredTableDetails]);

  const collapseVisibleTables = useCallback(() => {
    setExpandedTables((current) => {
      const next = new Set(current);
      for (const table of filteredTableDetails) {
        next.delete(table.name);
      }
      return next;
    });
  }, [filteredTableDetails]);

  return (
    <Card
      variant='subtle-compact'
      padding='sm'
      className='flex min-h-[420px] flex-col border-border/60 bg-card/40'
    >
      <div className='flex items-start justify-between gap-3'>
        <div className='min-w-0 space-y-1'>
          <h3 className='flex items-center gap-2 text-sm font-semibold text-white'>
            <DatabaseIcon className='size-4 shrink-0 text-emerald-200' />
            Database Tree
          </h3>
          <p className='truncate text-xs text-gray-400' title={databaseLabel}>
            {databaseLabel}
          </p>
        </div>
        {isFetching ? (
          <span className='shrink-0 rounded border border-cyan-400/30 bg-cyan-500/10 px-2 py-1 text-[11px] text-cyan-100'>
            Refreshing
          </span>
        ) : null}
      </div>

      <div className='mt-3 grid grid-cols-2 gap-2 text-xs'>
        <div className='rounded-md border border-white/10 bg-black/20 px-3 py-2'>
          <p className='text-[11px] uppercase text-gray-500'>Collections</p>
          <p className='mt-1 font-semibold text-gray-100'>
            {normalizedFilter === ''
              ? tableDetails.length.toLocaleString()
              : `${filteredTableDetails.length.toLocaleString()} / ${tableDetails.length.toLocaleString()}`}
          </p>
        </div>
        <div className='rounded-md border border-white/10 bg-black/20 px-3 py-2'>
          <p className='text-[11px] uppercase text-gray-500'>Database Size</p>
          <p className='mt-1 font-semibold text-gray-100'>{databaseSizeLabel}</p>
        </div>
      </div>

      <div className='mt-3 flex items-center gap-2'>
        <div className='relative min-w-0 flex-1'>
          <SearchIcon className='pointer-events-none absolute left-2.5 top-1/2 size-3.5 -translate-y-1/2 text-gray-500' />
          <input
            type='search'
            value={treeFilter}
            onChange={(event) => setTreeFilter(event.target.value)}
            placeholder='Filter tree...'
            aria-label='Filter database tree'
            className='h-8 w-full rounded-md border border-white/10 bg-black/20 pl-8 pr-2 text-xs text-gray-200 outline-none transition-colors placeholder:text-gray-500 focus:border-emerald-400/40'
          />
        </div>
        <button
          type='button'
          aria-label='Expand visible collections'
          title='Expand visible collections'
          onClick={expandVisibleTables}
          className='flex size-8 items-center justify-center rounded-md border border-white/10 bg-black/20 text-gray-400 hover:bg-white/10 hover:text-gray-100'
        >
          <ChevronDownIcon className='size-3.5' />
        </button>
        <button
          type='button'
          aria-label='Collapse visible collections'
          title='Collapse visible collections'
          onClick={collapseVisibleTables}
          className='flex size-8 items-center justify-center rounded-md border border-white/10 bg-black/20 text-gray-400 hover:bg-white/10 hover:text-gray-100'
        >
          <ChevronRightIcon className='size-3.5' />
        </button>
      </div>

      <div role='tree' aria-label='Database tree' className='mt-3 min-h-0 flex-1 overflow-auto'>
        <div
          role='treeitem'
          aria-expanded='true'
          className='flex items-center gap-2 rounded-md border border-white/10 bg-black/20 px-3 py-2 text-xs text-gray-200'
        >
          <HardDriveIcon className='size-3.5 shrink-0 text-gray-400' />
          <span className='min-w-0 flex-1 truncate' title={databaseLabel}>
            {databaseLabel}
          </span>
          <span className='shrink-0 font-mono text-[11px] text-gray-400'>
            {formatRows(totalRows)}
          </span>
        </div>

        <div role='group' className='mt-1 space-y-1 border-l border-white/10 pl-3'>
          {filteredTableDetails.length === 0 ? (
            <p className='px-2 py-3 text-xs text-gray-400'>
              {tableDetails.length === 0 ? 'No collections found.' : 'No matching collections.'}
            </p>
          ) : (
            filteredTableDetails.map((table) => {
              const isSelected = table.name === selectedTable;
              const isExpanded = expandedTables.has(table.name) || normalizedFilter !== '';
              const sizeLabel = getSizeLabel(table.sizeFormatted);
              return (
                <div
                  key={table.name}
                  role='treeitem'
                  aria-expanded={isExpanded}
                  aria-selected={isSelected}
                  className={cn(
                    'rounded-md border text-xs transition-colors',
                    isSelected
                      ? 'border-emerald-400/30 bg-emerald-500/15 text-emerald-50'
                      : 'border-transparent text-gray-300 hover:border-white/10 hover:bg-white/5'
                  )}
                >
                  <div className='grid w-full grid-cols-[auto_minmax(0,1fr)_auto] items-center gap-2 px-2 py-2'>
                    <button
                      type='button'
                      aria-label={`${isExpanded ? 'Collapse' : 'Expand'} ${table.name} collection`}
                      className='rounded p-0.5 text-gray-500 hover:bg-white/10 hover:text-gray-200'
                      onClick={(event) => {
                        event.stopPropagation();
                        toggleTable(table.name);
                      }}
                    >
                      {isExpanded ? (
                        <ChevronDownIcon className='size-3.5' />
                      ) : (
                        <ChevronRightIcon className='size-3.5' />
                      )}
                    </button>
                    <button
                      type='button'
                      aria-label={`Select ${table.name} collection`}
                      onClick={() => onSelectTable(table.name)}
                      className='flex min-w-0 items-center gap-2 text-left'
                    >
                      <Table2Icon
                        className={cn(
                          'size-3.5 shrink-0',
                          isSelected ? 'text-emerald-200' : 'text-gray-500'
                        )}
                      />
                      <span className='min-w-0 truncate font-mono' title={table.name}>
                        {table.name}
                      </span>
                    </button>
                    <span className='flex shrink-0 items-center gap-2 text-[11px] text-gray-400'>
                      <span>{formatRows(table.rowEstimate)}</span>
                      <span>{sizeLabel}</span>
                    </span>
                  </div>

                  {isExpanded ? (
                    <div role='group' className='space-y-2 border-t border-white/10 px-3 py-2'>
                      <div className='flex items-center gap-2 text-[11px] font-medium uppercase text-gray-500'>
                        <Columns3Icon className='size-3.5' />
                        Fields
                        <span className='ml-auto font-mono'>
                          {table.columns.length.toLocaleString()}
                        </span>
                      </div>
                      {table.columns.length === 0 ? (
                        <p className='pl-5 text-[11px] text-gray-500'>No sampled fields.</p>
                      ) : (
                        <div className='space-y-1 pl-5'>
                          {table.columns.map((column) => (
                            <div
                              key={column.name}
                              role='treeitem'
                              aria-label={`${table.name}.${column.name} field`}
                              className='grid grid-cols-[minmax(0,1fr)_auto] gap-2 text-[11px] text-gray-400'
                            >
                              <span className='min-w-0 truncate font-mono' title={column.name}>
                                {column.name}
                              </span>
                              <span className='shrink-0 truncate text-gray-500' title={column.type}>
                                {column.type}
                              </span>
                            </div>
                          ))}
                        </div>
                      )}

                      {table.indexes.length > 0 ? (
                        <>
                          <div className='flex items-center gap-2 text-[11px] font-medium uppercase text-gray-500'>
                            <KeyRoundIcon className='size-3.5' />
                            Indexes
                            <span className='ml-auto font-mono'>
                              {table.indexes.length.toLocaleString()}
                            </span>
                          </div>
                          <div className='space-y-1 pl-5'>
                            {table.indexes.map((index) => (
                              <div
                                key={index.name}
                                role='treeitem'
                                aria-label={`${table.name}.${index.name} index`}
                                className='grid grid-cols-[minmax(0,1fr)_auto] gap-2 text-[11px] text-gray-400'
                              >
                                <span className='min-w-0 truncate font-mono' title={index.name}>
                                  {index.name}
                                </span>
                                <span
                                  className='shrink-0 truncate text-gray-500'
                                  title={index.definition ?? index.columns.join(', ')}
                                >
                                  {index.isUnique ? 'unique' : index.columns.join(', ') || 'index'}
                                </span>
                              </div>
                            ))}
                          </div>
                        </>
                      ) : null}
                    </div>
                  ) : null}
                </div>
              );
            })
          )}
        </div>
      </div>
    </Card>
  );
}

'use client';

import { CloudUploadIcon, DownloadIcon, RefreshCwIcon } from 'lucide-react';
import Link from 'next/link';
import type { JSX } from 'react';

import type {
  DatabaseEngineManagedMongoApplication,
  DatabaseEngineManagedMongoDatabase,
  MongoSource,
} from '@/shared/contracts/database';
import { Badge, Button } from '@/shared/ui/primitives.public';

import {
  useDatabaseEngineActionsContext,
  useDatabaseEngineStateContext,
} from '../../context/DatabaseEngineContext';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local',
  cloud: 'Cloud',
};

export const buildManagedMongoCrudHref = (
  application: DatabaseEngineManagedMongoApplication,
  source: MongoSource = 'local'
): string =>
  `/admin/databases/engine?view=crud&application=${encodeURIComponent(
    application
  )}&source=${source}`;

const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getEndpointStatusLabel = (
  endpoint: DatabaseEngineManagedMongoDatabase['local']
): string => {
  if (!endpoint.configured) return 'not configured';
  if (endpoint.reachable === true) return 'ready';
  if (endpoint.reachable === false) return 'unreachable';
  return 'unknown';
};

function ManagedMongoDatabaseScopeCard({
  activeApplication,
  activeSource,
  backupDisabled,
  database,
  syncDisabled,
}: {
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
  backupDisabled: boolean;
  database: DatabaseEngineManagedMongoDatabase;
  syncDisabled: boolean;
}): JSX.Element {
  const { backupManagedMongo, syncManagedMongo } = useDatabaseEngineActionsContext();
  const isActive = database.application === activeApplication;
  const isLocalActive = isActive && activeSource === 'local';
  const isCloudActive = isActive && activeSource === 'cloud';
  const isBackupDisabled = backupDisabled || !database.canBackupLocal;
  const isPushDisabled = syncDisabled || !database.canPushToCloud;
  const isPullDisabled = syncDisabled || !database.canPullFromCloud;

  return (
    <div
      className={`rounded-md border p-3 ${
        isActive
          ? 'border-emerald-400/40 bg-emerald-500/10'
          : 'border-white/10 bg-black/20'
      }`}
    >
      <div className='flex flex-wrap items-start justify-between gap-3'>
        <div className='min-w-0 space-y-1'>
          <h3 className='truncate text-sm font-semibold text-white'>{database.label}</h3>
          <p className='text-xs text-gray-400'>
            Local {getEndpointStatusLabel(database.local)} - Cloud{' '}
            {getEndpointStatusLabel(database.cloud)}
          </p>
          <p className='text-xs text-gray-400'>
            Local {database.local.collectionCount.toLocaleString()} collections -{' '}
            {formatBytes(database.local.databaseSizeBytes)}
          </p>
          <p className='text-xs text-gray-400'>
            Cloud {database.cloud.collectionCount.toLocaleString()} collections -{' '}
            {formatBytes(database.cloud.databaseSizeBytes)}
          </p>
        </div>
        <Badge variant={isActive ? 'active' : 'outline'} className='border-white/10 text-xs'>
          {isActive ? `Open ${SOURCE_LABELS[activeSource]}` : 'Available'}
        </Badge>
      </div>

      {database.syncIssue ? (
        <p className='mt-2 line-clamp-2 text-xs text-amber-100' title={database.syncIssue}>
          {database.syncIssue}
        </p>
      ) : null}

      <div className='mt-3 flex flex-wrap gap-2'>
        <Button asChild variant={isLocalActive ? 'secondary' : 'outline'} size='xs'>
          <Link href={buildManagedMongoCrudHref(database.application, 'local')}>Local Tables</Link>
        </Button>
        <Button asChild variant={isCloudActive ? 'secondary' : 'outline'} size='xs'>
          <Link href={buildManagedMongoCrudHref(database.application, 'cloud')}>Cloud Tables</Link>
        </Button>
        <Button
          type='button'
          variant='outline'
          size='xs'
          disabled={isBackupDisabled}
          onClick={() => {
            void backupManagedMongo(database.application);
          }}
        >
          <DownloadIcon className='size-3.5' />
          Backup
        </Button>
        <Button
          type='button'
          size='xs'
          disabled={isPushDisabled}
          onClick={() => {
            void syncManagedMongo('local_to_cloud', database.application);
          }}
        >
          <CloudUploadIcon className='size-3.5' />
          Push
        </Button>
        <Button
          type='button'
          variant='outline'
          size='xs'
          disabled={isPullDisabled}
          onClick={() => {
            void syncManagedMongo('cloud_to_local', database.application);
          }}
        >
          <RefreshCwIcon className='size-3.5' />
          Pull
        </Button>
      </div>
    </div>
  );
}

export function ManagedMongoScopePanel({
  activeApplication,
  activeSource,
}: {
  activeApplication: DatabaseEngineManagedMongoApplication;
  activeSource: MongoSource;
}): JSX.Element {
  const {
    managedMongoDatabases,
    operationControls,
    isBackingUpManagedMongo,
    isSyncingManagedMongo,
  } = useDatabaseEngineStateContext();
  const { backupManagedMongo, refetchAll, syncManagedMongo } = useDatabaseEngineActionsContext();

  if (managedMongoDatabases === undefined) {
    return (
      <div className='rounded-md border border-white/10 bg-black/20 p-3 text-sm text-gray-300'>
        Loading managed MongoDB files...
      </div>
    );
  }

  const backupDisabled =
    isBackingUpManagedMongo ||
    !operationControls.allowManualBackupRunNow ||
    !managedMongoDatabases.canBackupAllLocal;
  const syncDisabled =
    isSyncingManagedMongo ||
    !operationControls.allowManualFullSync ||
    !managedMongoDatabases.canPushAllToCloud;
  const pullDisabled =
    isSyncingManagedMongo ||
    !operationControls.allowManualFullSync ||
    !managedMongoDatabases.canPullAllFromCloud;
  const cardBackupDisabled =
    isBackingUpManagedMongo ||
    !operationControls.allowManualBackupRunNow ||
    !managedMongoDatabases.backupStorage.canWriteBackups;
  const cardSyncDisabled = isSyncingManagedMongo || !operationControls.allowManualFullSync;

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-card/30 p-3'>
      <div className='flex flex-wrap items-center justify-between gap-3'>
        <div className='space-y-1'>
          <h2 className='text-sm font-semibold text-white'>Managed MongoDB Files</h2>
          <p className='text-xs text-gray-400'>
            Backup root: {managedMongoDatabases.backupRoot}
          </p>
        </div>
        <div className='flex flex-wrap gap-2'>
          <Button type='button' variant='outline' size='xs' onClick={refetchAll}>
            <RefreshCwIcon className='size-3.5' />
            Refresh
          </Button>
          <Button
            type='button'
            variant='outline'
            size='xs'
            disabled={backupDisabled}
            onClick={() => {
              void backupManagedMongo('all');
            }}
          >
            <DownloadIcon className='size-3.5' />
            Backup All
          </Button>
          <Button
            type='button'
            size='xs'
            disabled={syncDisabled}
            onClick={() => {
              void syncManagedMongo('local_to_cloud', 'all');
            }}
          >
            <CloudUploadIcon className='size-3.5' />
            Push All
          </Button>
          <Button
            type='button'
            variant='outline'
            size='xs'
            disabled={pullDisabled}
            onClick={() => {
              void syncManagedMongo('cloud_to_local', 'all');
            }}
          >
            <RefreshCwIcon className='size-3.5' />
            Pull All
          </Button>
        </div>
      </div>

      <div className='grid gap-3 lg:grid-cols-2 xl:grid-cols-4'>
        {managedMongoDatabases.databases.map((database) => (
          <ManagedMongoDatabaseScopeCard
            key={database.application}
            activeApplication={activeApplication}
            activeSource={activeSource}
            backupDisabled={cardBackupDisabled}
            database={database}
            syncDisabled={cardSyncDisabled}
          />
        ))}
      </div>
    </div>
  );
}

'use client';

import Link from 'next/link';
import { CloudUploadIcon, DatabaseIcon, DownloadIcon, PencilIcon, RefreshCwIcon } from 'lucide-react';
import type { JSX } from 'react';

import type {
  DatabaseEngineManagedMongoApplicationTarget,
  DatabaseEngineManagedMongoCollectionStats,
  DatabaseEngineManagedMongoDatabase,
  DatabaseEngineManagedMongoEndpoint,
  DatabaseEngineMongoPendingSyncRequest,
  MongoSource,
} from '@/shared/contracts/database';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { FormSection } from '@/shared/ui/forms-and-actions.public';
import { Button, Card } from '@/shared/ui/primitives.public';

import {
  useDatabaseEngineActionsContext,
  useDatabaseEngineStateContext,
} from '../../context/DatabaseEngineContext';
import { buildManagedMongoCrudHref } from '../crud/ManagedMongoScopePanel';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local',
  cloud: 'Cloud',
};

const isPendingSyncTarget = (
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null,
  direction: 'cloud_to_local' | 'local_to_cloud',
  application: DatabaseEngineManagedMongoApplicationTarget
): boolean =>
  pendingSync !== null &&
  pendingSync.direction === direction &&
  pendingSync.application === application;

const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getEndpointStatus = (
  endpoint: DatabaseEngineManagedMongoEndpoint
): { status: string; variant: 'active' | 'error' | 'pending' } => {
  if (!endpoint.configured) return { status: 'Not configured', variant: 'pending' };
  if (endpoint.reachable === true) return { status: 'Reachable', variant: 'active' };
  if (endpoint.reachable === false) return { status: 'Unreachable', variant: 'error' };
  return { status: 'Unknown', variant: 'pending' };
};

function CollectionSizeList({
  collections,
}: {
  collections: DatabaseEngineManagedMongoCollectionStats[];
}): JSX.Element {
  if (collections.length === 0) {
    return <p className='text-xs text-gray-400'>No collection stats available.</p>;
  }

  return (
    <div className='max-h-52 overflow-auto rounded-md border border-white/10'>
      <table className='w-full text-left text-[11px]'>
        <thead className='sticky top-0 bg-gray-950 text-gray-400'>
          <tr>
            <th className='px-2 py-1.5 font-medium'>Collection</th>
            <th className='px-2 py-1.5 text-right font-medium'>Docs</th>
            <th className='px-2 py-1.5 text-right font-medium'>Size</th>
          </tr>
        </thead>
        <tbody>
          {collections.map((collection) => (
            <tr key={collection.name} className='border-t border-white/10 text-gray-300'>
              <td className='max-w-40 truncate px-2 py-1.5 font-mono' title={collection.name}>
                {collection.name}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {collection.documentCount?.toLocaleString() ?? 'n/a'}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {formatBytes(collection.totalSizeBytes)}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function EndpointPanel({
  endpoint,
}: {
  endpoint: DatabaseEngineManagedMongoEndpoint;
}): JSX.Element {
  const status = getEndpointStatus(endpoint);

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-black/20 p-3'>
      <div className='flex items-start justify-between gap-2'>
        <div className='space-y-1'>
          <h4 className='text-xs font-semibold uppercase text-gray-300'>
            {SOURCE_LABELS[endpoint.source]}
          </h4>
          <p className='text-xs text-gray-400'>{endpoint.dbName ?? 'No database selected'}</p>
        </div>
        <StatusBadge status={status.status} variant={status.variant} size='sm' />
      </div>

      <div className='space-y-1 text-xs text-gray-300'>
        <p className='truncate' title={endpoint.maskedUri ?? ''}>
          {endpoint.maskedUri ?? 'No URI configured'}
        </p>
        <p>Database size: {formatBytes(endpoint.databaseSizeBytes)}</p>
        <p>Collections: {endpoint.collectionCount.toLocaleString()}</p>
        <p>Collection storage: {formatBytes(endpoint.collectionsSizeBytes)}</p>
        {endpoint.healthError ? <p className='text-rose-200'>{endpoint.healthError}</p> : null}
      </div>

      <CollectionSizeList collections={endpoint.collections} />
    </div>
  );
}

function ManagedDatabaseCard({
  database,
  backupDisabled,
  syncDisabled,
  pendingSync,
}: {
  database: DatabaseEngineManagedMongoDatabase;
  backupDisabled: boolean;
  syncDisabled: boolean;
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null;
}): JSX.Element {
  const { backupManagedMongo, syncManagedMongo } = useDatabaseEngineActionsContext();
  const isBackupDisabled = backupDisabled || !database.canBackupLocal;
  const isPushDisabled = syncDisabled || !database.canPushToCloud;
  const isPullDisabled = syncDisabled || !database.canPullFromCloud;
  const isPushing = isPendingSyncTarget(pendingSync, 'local_to_cloud', database.application);
  const isPulling = isPendingSyncTarget(pendingSync, 'cloud_to_local', database.application);

  return (
    <Card variant='subtle' padding='md' className='space-y-4 border-white/10'>
      <div className='flex flex-wrap items-start justify-between gap-3'>
        <div className='space-y-1'>
          <h3 className='flex items-center gap-2 text-sm font-semibold text-white'>
            <DatabaseIcon className='size-4 text-emerald-200' />
            {database.label}
          </h3>
          {database.syncIssue ? (
            <p className='text-xs leading-relaxed text-amber-100'>{database.syncIssue}</p>
          ) : null}
        </div>
        <div className='flex flex-wrap gap-2'>
          <Button asChild type='button' variant='outline' size='sm'>
            <Link href={buildManagedMongoCrudHref(database.application, 'local')}>
              <PencilIcon className='size-3.5' />
              Local Tables
            </Link>
          </Button>
          <Button asChild type='button' variant='outline' size='sm'>
            <Link href={buildManagedMongoCrudHref(database.application, 'cloud')}>
              <PencilIcon className='size-3.5' />
              Cloud Tables
            </Link>
          </Button>
          <Button
            type='button'
            variant='outline'
            size='sm'
            disabled={isBackupDisabled}
            onClick={() => {
              void backupManagedMongo(database.application);
            }}
          >
            <DownloadIcon className='size-3.5' />
            Backup
          </Button>
          <Button
            type='button'
            size='sm'
            disabled={isPushDisabled}
            loading={isPushing}
            loadingText='Pushing...'
            onClick={() => {
              void syncManagedMongo('local_to_cloud', database.application);
            }}
          >
            <CloudUploadIcon className='size-3.5' />
            Push
          </Button>
          <Button
            type='button'
            variant='outline'
            size='sm'
            disabled={isPullDisabled}
            loading={isPulling}
            loadingText='Pulling...'
            onClick={() => {
              void syncManagedMongo('cloud_to_local', database.application);
            }}
          >
            <RefreshCwIcon className='size-3.5' />
            Pull
          </Button>
        </div>
      </div>

      <div className='grid gap-4 xl:grid-cols-2'>
        <EndpointPanel endpoint={database.local} />
        <EndpointPanel endpoint={database.cloud} />
