import { z } from 'zod';

import {
  databaseEngineBackupScheduleSchema,
  databaseEngineBackupTargetScheduleSchema,
  databaseEngineOperationControlsSchema,
  databaseEnginePolicySchema,
  databaseEngineProviderSchema,
  databaseEngineServiceSchema,
} from '@/shared/contracts/database';
import { validationError } from '@/shared/errors/app-error';
import {
  DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE,
  DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS,
  DEFAULT_DATABASE_ENGINE_POLICY,
  type DatabaseEngineBackupSchedule,
  type DatabaseEngineOperationControls,
  type DatabaseEnginePolicy,
  type DatabaseEngineProvider,
  type DatabaseEngineServiceRoute,
} from '@/shared/lib/db/database-engine-constants';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


const DATABASE_ENGINE_TIME_UTC_RE = /^([01]\d|2[0-3]):([0-5]\d)$/;

const isoDateStringSchema = z
  .string()
  .trim()
  .min(1)
  .refine((value: string): boolean => Number.isFinite(Date.parse(value)), {
    message: 'Expected ISO date string.',
  });

const nullableIsoDateStringSchema = isoDateStringSchema.nullable();

const databaseEnginePolicyStrictSchema = databaseEnginePolicySchema.strict();
const databaseEngineOperationControlsStrictSchema = databaseEngineOperationControlsSchema.strict();
const databaseEngineBackupTargetScheduleStrictSchema = databaseEngineBackupTargetScheduleSchema
  .extend({
    intervalDays: z.number().int().min(1).max(365),
    weekday: z.number().int().min(0).max(6),
    timeUtc: z.string().regex(DATABASE_ENGINE_TIME_UTC_RE),
    lastQueuedAt: nullableIsoDateStringSchema,
    lastRunAt: nullableIsoDateStringSchema,
    lastJobId: z.string().trim().min(1).nullable(),
    lastError: z.string().trim().min(1).nullable(),
    nextDueAt: nullableIsoDateStringSchema,
  })
  .strict();

const databaseEngineBackupScheduleStrictSchema = databaseEngineBackupScheduleSchema
  .extend({
    lastCheckedAt: nullableIsoDateStringSchema,
    mongodb: databaseEngineBackupTargetScheduleStrictSchema,
  })
  .strict();

const parseNonEmptyJsonObject = (
  raw: string | null | undefined,
  key: string
): Record<string, unknown> | null => {
  if (typeof raw !== 'string') return null;
  const trimmedRaw = raw.trim();
  if (!trimmedRaw) return null;

  let parsed: unknown;
  try {
    parsed = JSON.parse(trimmedRaw);
  } catch (error) {
    logClientError(error);
    throw validationError(`Invalid ${key} settings payload.`, {
      source: 'database_engine.settings',
      key,
      reason: 'invalid_json',
      cause: error instanceof Error ? error.message : 'unknown_error',
    });
  }

  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    throw validationError(`Invalid ${key} settings payload.`, {
      source: 'database_engine.settings',
      key,
      reason: 'invalid_shape',
    });
  }

  return parsed as Record<string, unknown>;
};

const parseWithSchema = <T>(
  key: string,
  raw: string | null | undefined,
  schema: z.ZodType<T>,
  fallback: T
): T => {
  const parsed = parseNonEmptyJsonObject(raw, key);
  if (!parsed) return fallback;

  const result = schema.safeParse(parsed);
  if (!result.success) {
    throw validationError(`Invalid ${key} settings payload.`, {
      source: 'database_engine.settings',
      key,
      reason: 'schema_validation_failed',
      issues: result.error.flatten(),
    });
  }

  return result.data;
};

export const parseDatabaseEnginePolicySetting = (
  raw: string | null | undefined
): DatabaseEnginePolicy =>
  parseWithSchema(
    'database engine policy',
    raw,
    databaseEnginePolicyStrictSchema,
    DEFAULT_DATABASE_ENGINE_POLICY
  );

export const parseDatabaseEngineOperationControlsSetting = (
  raw: string | null | undefined
): DatabaseEngineOperationControls =>
  parseWithSchema(
    'database engine operation controls',
    raw,
    databaseEngineOperationControlsStrictSchema,
    DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS
  );

export const parseDatabaseEngineBackupScheduleSetting = (
  raw: string | null | undefined
): DatabaseEngineBackupSchedule =>
  parseWithSchema(
    'database engine backup schedule',
    raw,
    databaseEngineBackupScheduleStrictSchema,
    DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE
  );

export const parseDatabaseEngineServiceRouteMapSetting = (
  raw: string | null | undefined
): Partial<Record<DatabaseEngineServiceRoute, DatabaseEngineProvider>> => {
  const parsed = parseNonEmptyJsonObject(raw, 'database engine service route map');
  if (!parsed) return {};

  const result: Partial<Record<DatabaseEngineServiceRoute, DatabaseEngineProvider>> = {};
  Object.entries(parsed).forEach(([service, provider]: [string, unknown]): void => {
    const serviceValidation = databaseEngineServiceSchema.safeParse(service);
    if (!serviceValidation.success) {
      throw validationError('Invalid database engine service route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine service route map',
        reason: 'invalid_service',
        service,
      });
    }
    const providerValidation = databaseEngineProviderSchema.safeParse(provider);
    if (!providerValidation.success) {
      throw validationError('Invalid database engine service route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine service route map',
        reason: 'invalid_provider',
        service,
        provider,
      });
    }
    result[serviceValidation.data] = providerValidation.data;
  });

  return result;
};

export const parseDatabaseEngineCollectionRouteMapSetting = (
  raw: string | null | undefined
): Record<string, DatabaseEngineProvider> => {
  const parsed = parseNonEmptyJsonObject(raw, 'database engine collection route map');
  if (!parsed) return {};

  const result: Record<string, DatabaseEngineProvider> = {};
  Object.entries(parsed).forEach(([collection, provider]: [string, unknown]): void => {
    const normalizedCollection = collection.trim();
    if (!normalizedCollection) {
      throw validationError('Invalid database engine collection route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine collection route map',
        reason: 'invalid_collection',
      });
    }
    const providerValidation = databaseEngineProviderSchema.safeParse(provider);
    if (!providerValidation.success) {
      throw validationError('Invalid database engine collection route map payload.', {
        source: 'database_engine.settings',
        key: 'database engine collection route map',
        reason: 'invalid_provider',
        collection: normalizedCollection,
        provider,
      });
    }
    result[normalizedCollection] = providerValidation.data;
  });

  return result;
};

'use client';

/**
 * CRUD Panel State Management Hook
 *
 * Manages the complete state for database CRUD operations interface.
 * Provides functionality for:
 * - Table selection and navigation
 * - Pagination and data loading
 * - Modal state management (add/edit/delete)
 * - SQL query execution and result handling
 * - Real-time data synchronization
 *
 * This hook centralizes all database interaction logic for the
 * admin database management interface, ensuring consistent
 * state management across CRUD operations.
 */

import { useCallback, useEffect, useMemo, useState } from 'react';
import type { DatabaseColumnInfo, DatabaseTableDetail, DatabaseType } from '@/shared/contracts/database';
import type { ListQuery } from '@/shared/contracts/ui/queries';
import { ApiError } from '@/shared/lib/api-client';
import { createListQueryV2 } from '@/shared/lib/query-factories-v2';
import { QUERY_KEYS } from '@/shared/lib/query-keys';
import { executeSqlQuery } from '../api';
import { useDatabaseConfig, useDatabaseData } from '../context/DatabaseContext';
import { useCrudMutations, type UseCrudMutationsReturn } from './crud/useCrudMutations';

// Result structure for paginated table data
type CrudRowsResult = {
  rows: Record<string, unknown>[];
  totalRows: number;
};

export interface UseCrudPanelStateReturn
  extends Omit<UseCrudMutationsReturn, 'handleAdd' | 'handleEdit' | 'handleDelete'> {
  selectedTable: string; // Currently selected database table
  setSelectedTable: (table: string) => void;
  page: number; // Current pagination page
  setPage: (page: number) => void;
  pageSize: number; // Number of rows per page
  setPageSize: (size: number) => void;
  showAddModal: boolean; // Add new record modal visibility
  setShowAddModal: (show: boolean) => void;
  editingRow: Record<string, unknown> | null;
  setEditingRow: (row: Record<string, unknown> | null) => void;
  deletingRow: Record<string, unknown> | null;
  setDeletingRow: (row: Record<string, unknown> | null) => void;
  tableDetail: DatabaseTableDetail | undefined;
  rows: Record<string, unknown>[];
  totalRows: number;
  isLoadingRows: boolean;
  maxPage: number;
  fetchRows: () => void;
  handleAdd: (data: Record<string, unknown>) => void;
  handleEdit: (data: Record<string, unknown>) => void;
  handleDelete: () => void;
  dbType: DatabaseType;
  tableDetails: DatabaseTableDetail[];
  columns: DatabaseColumnInfo[];
  rowsQuery: ListQuery<CrudRowsResult, CrudRowsResult>;
}

export function useCrudPanelState(props: {
  tableDetails?: DatabaseTableDetail[];
  defaultTable?: string;
  dbType?: DatabaseType;
}): UseCrudPanelStateReturn {
  const dbKeys = QUERY_KEYS.system.databases;
  const { dbType: contextDbType, application, source } = useDatabaseConfig();
  const { tableDetails: contextTableDetails, refresh: refreshDatabasePreview } = useDatabaseData();
  const dbType = props.dbType ?? contextDbType;
  const tableDetails = props.tableDetails ?? contextTableDetails;

  const [selectedTable, setSelectedTable] = useState(props.defaultTable ?? '');
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(20);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingRow, setEditingRow] = useState<Record<string, unknown> | null>(null);
  const [deletingRow, setDeletingRow] = useState<Record<string, unknown> | null>(null);

  const mutationTarget = useMemo(() => ({ application, source }), [application, source]);
  const mutations = useCrudMutations(mutationTarget);
  const { setMutationError, setSuccessMessage } = mutations;

  useEffect(() => {
    setSelectedTable(props.defaultTable ?? '');
    setPage(1);
    setShowAddModal(false);
    setEditingRow(null);
    setDeletingRow(null);
    setMutationError(null);
    setSuccessMessage(null);
  }, [application, source, props.defaultTable, setMutationError, setSuccessMessage]);

  useEffect(() => {
    if (selectedTable === '') return;
    if (tableDetails.some((table) => table.name === selectedTable)) return;
    setSelectedTable('');
    setPage(1);
  }, [selectedTable, tableDetails]);

  const tableDetail = useMemo(
    () => tableDetails.find((t) => t.name === selectedTable),
    [tableDetails, selectedTable]
  );

  const rowsQuery = createListQueryV2<CrudRowsResult, CrudRowsResult>({
    queryKey: dbKeys.crudRows({ dbType, selectedTable, page, pageSize, application, source }),
    enabled: selectedTable !== '',
    queryFn: async () => {
      if (selectedTable === '') return { rows: [], totalRows: 0 };
      if (dbType !== 'mongodb') throw new ApiError('Only MongoDB CRUD operations are supported.', 400);

      const mongoResult = await executeSqlQuery({
        type: 'mongodb',
        application,
        source,
        collection: selectedTable,
        operation: 'find',
        filter: {},
        skip: (page - 1) * pageSize,
        limit: pageSize,
        sort: { _id: 1 },
      });

      if (mongoResult.error) throw new ApiError(mongoResult.error, 400);

      return {
        rows: mongoResult.rows,
        totalRows: mongoResult.rowCount ?? mongoResult.rows.length,
      };
    },
    meta: {
      source: 'database.hooks.useCrudPanelState',
      operation: 'list',
      resource: 'system.databases.crud-rows',
      domain: 'database',
      tags: ['database', 'crud'],
      description: 'Loads rows for Database Engine CRUD table management.',
    },
  });

  const fetchRows = useCallback(() => {
    if (selectedTable === '') return;
    mutations.setMutationError(null);
    mutations.setSuccessMessage(null);
    void rowsQuery.refetch();
    refreshDatabasePreview();
  }, [refreshDatabasePreview, rowsQuery, selectedTable, mutations]);

  const handleAdd = (data: Record<string, unknown>) => {
    mutations.handleAdd(selectedTable, data, () => {
      setShowAddModal(false);
      void rowsQuery.refetch();
      refreshDatabasePreview();
    });
  };

  const handleEdit = (data: Record<string, unknown>) => {
    if (!editingRow) return;
    mutations.handleEdit(selectedTable, editingRow, data, () => {
      setEditingRow(null);
      void rowsQuery.refetch();
      refreshDatabasePreview();
    });
  };

  const handleDelete = () => {
    if (!deletingRow) return;
    mutations.handleDelete(selectedTable, deletingRow, () => {
      setDeletingRow(null);
      void rowsQuery.refetch();
      refreshDatabasePreview();
    });
  };

  return {
    ...mutations,
    selectedTable,
    setSelectedTable,
    page,
    setPage,
    pageSize,
    setPageSize,
    showAddModal,
    setShowAddModal,
    editingRow,
    setEditingRow,
    deletingRow,
    setDeletingRow,
    tableDetail,
    rows: rowsQuery.data?.rows ?? [],
    totalRows: rowsQuery.data?.totalRows ?? 0,
    isLoadingRows: rowsQuery.isLoading,
    maxPage: Math.ceil((rowsQuery.data?.totalRows ?? 0) / pageSize),
    fetchRows,
    handleAdd,
    handleEdit,
    handleDelete,
    dbType,
    tableDetails,
    columns: tableDetail?.columns ?? [],
    rowsQuery,
  };
}

