  const [activeTargetTimeLocalDraft, setActiveTargetTimeLocalDraft] = useState('02:00');

  const { toast } = useToast();
  const isProd = process.env['NODE_ENV'] === 'production';
  const settingsQuery = useSettingsMap({ scope: 'all' });
  const updateSetting = useUpdateSetting();
  const lastSettingsValidationSignatureRef = useRef<string | null>(null);

  const backupsQuery = useDatabaseBackups(activeTab);
  const data = useMemo(() => backupsQuery.data ?? [], [backupsQuery.data]);

  const createBackup = useCreateBackupMutation();
  const restoreBackup = useRestoreBackupMutation();
  const uploadBackup = useUploadBackupMutation();
  const deleteBackup = useDeleteBackupMutation();

  const readPayload = <T,>(result: { payload: T | unknown }): T => result.payload as T;

  const parsedSettings = useMemo(() => {
    const errors: string[] = [];
    const loggedErrors: unknown[] = [];

    const parseSetting = <T>(parser: () => T, fallback: T): T => {
      try {
        return parser();
      } catch (error) {
        logClientError(error);
        errors.push(error instanceof Error ? error.message : 'Invalid backup settings payload.');
        loggedErrors.push(error);
        return fallback;
      }
    };

    return {
      operationControls: parseSetting(
        () =>
          parseDatabaseEngineOperationControlsSetting(
            settingsQuery.data?.get(DATABASE_ENGINE_OPERATION_CONTROLS_KEY)
          ),
        DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS
      ),
      backupSchedule: parseSetting(
        () =>
          parseDatabaseEngineBackupScheduleSetting(
            settingsQuery.data?.get(DATABASE_ENGINE_BACKUP_SCHEDULE_KEY)
          ),
        DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE
      ),
      errors,
      loggedErrors,
    };
  }, [settingsQuery.data]);

  const operationControls = parsedSettings.operationControls;
  const backupSchedule = parsedSettings.backupSchedule;
  const settingsValidationErrors = parsedSettings.errors;

  const backupRunNowAllowed = operationControls.allowManualBackupRunNow;
  const backupMaintenanceAllowed = operationControls.allowManualBackupMaintenance;
  const schedulerEnabled = backupSchedule.schedulerEnabled;
  const repeatSchedulerTickEnabled = backupSchedule.repeatTickEnabled;
  const isBackupScheduleSaving = updateSetting.isPending;
  const activeTargetKey: DatabaseEngineBackupType = 'mongodb';
  const activeTargetSchedule = backupSchedule[activeTargetKey];
  const activeTargetTimeLocalCurrent = useMemo(
    () => utcHmToLocalHm(activeTargetSchedule.timeUtc) ?? activeTargetSchedule.timeUtc,
    [activeTargetSchedule.timeUtc]
  );
  const activeTargetTimeLocalDraftValid = isValidDatabaseEngineBackupTimeUtc(
    activeTargetTimeLocalDraft
  );

  useEffect(() => {
    setSchedulerEnabledDraft(backupSchedule.schedulerEnabled);
    setRepeatTickEnabledDraft(backupSchedule.repeatTickEnabled);
    setActiveTargetEnabledDraft(activeTargetSchedule.enabled);
    setActiveTargetTimeLocalDraft(activeTargetTimeLocalCurrent);
  }, [
    backupSchedule.schedulerEnabled,
    backupSchedule.repeatTickEnabled,
    activeTargetSchedule.enabled,
    activeTargetTimeLocalCurrent,
  ]);

  useEffect(() => {
    if (parsedSettings.loggedErrors.length === 0) {
      lastSettingsValidationSignatureRef.current = null;
      return;
    }

    const signature = settingsValidationErrors.join('::');
    if (lastSettingsValidationSignatureRef.current === signature) return;
    lastSettingsValidationSignatureRef.current = signature;

    parsedSettings.loggedErrors.forEach((error: unknown): void => {
      logClientError(error, {
        context: {
          source: 'useDatabaseBackupsState',
          action: 'parsePersistedSettings',
        },
      });
    });

    toast(settingsValidationErrors[0] ?? 'Invalid database backup settings payload.', {
      variant: 'error',
    });
  }, [parsedSettings.loggedErrors, settingsValidationErrors, toast]);

  const isBackupScheduleDirty = useMemo(
    () =>
      schedulerEnabledDraft !== backupSchedule.schedulerEnabled ||
      repeatTickEnabledDraft !== backupSchedule.repeatTickEnabled ||
      activeTargetEnabledDraft !== activeTargetSchedule.enabled ||
      activeTargetTimeLocalDraft !== activeTargetTimeLocalCurrent,
    [
      schedulerEnabledDraft,
      backupSchedule.schedulerEnabled,
      repeatTickEnabledDraft,
      backupSchedule.repeatTickEnabled,
      activeTargetEnabledDraft,
      activeTargetSchedule.enabled,
      activeTargetTimeLocalDraft,
      activeTargetTimeLocalCurrent,
    ]
  );

  const openLogModal = useCallback((content: string): void => {
    setLogModalContent(content);
    setIsLogModalOpen(true);
  }, []);

  const closeLogModal = useCallback((): void => {
    setIsLogModalOpen(false);
    setLogModalContent('');
  }, []);

  const handleRestoreRequest = useCallback((backup: DatabaseInfo): void => {
    setSelectedBackupForRestore(backup.name);
    setIsRestoreModalOpen(true);
  }, []);

  const handleRestoreConfirm = async (truncate: boolean): Promise<void> => {
    const backupName = selectedBackupForRestore;
    setIsRestoreModalOpen(false);
    setSelectedBackupForRestore(null);

    if (!backupName) return;

    try {
      const result = await restoreBackup.mutateAsync({
        dbType: activeTab,
        backupName,
        truncateBeforeRestore: truncate,
      });
      const { ok } = result;
      const payload = readPayload<DatabaseRestoreResponse>(result);
      const log = String(payload.log ?? 'No log available.');

      if (ok) {
        openLogModal(
          `${payload.message ?? 'Backup restored successfully.'}

---LOG---
${log}`
        );
      } else {
        const meta = [
          payload.errorId ? `Error ID: ${payload.errorId}` : null,
          payload.stage ? `Stage: ${payload.stage}` : null,
          payload.backupName ? `Backup: ${payload.backupName}` : null,
        ]
          .filter(Boolean)
          .join('\n');

        openLogModal(
          `${payload.error ?? 'Failed to restore backup.'}${
            meta
              ? `

${meta}`
              : ''
          }

---LOG---
${log}`
        );
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'restoreBackup',
        backupName,
        dbType: activeTab,
      });
      openLogModal(`An error occurred during restoration.

${String(error)}`);
    }
  };

  const handleBackup = async (): Promise<void> => {
    try {
      const result = await createBackup.mutateAsync(activeTab);
      const { ok } = result;
      const payload = readPayload<DatabaseBackupResponse>(result);
      const log = String(payload.log ?? 'No log available.');
      if (ok) {
        if (payload.jobId) {
          toast(payload.message ?? `Database backup job queued (job: ${payload.jobId}).`, {
            variant: 'success',
          });
          return;
        }

        if (payload.warning) {
          openLogModal(`${payload.message ?? 'Backup created'}: ${payload.warning}

---LOG---
${log}`);
        } else {
          openLogModal(`${payload.message ?? 'Backup created successfully.'}

---LOG---
${log}`);
        }
      } else {
        openLogModal(`${payload.error ?? 'Failed to create backup.'}

---LOG---
${log}`);
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'createBackup',
        dbType: activeTab,
      });
      openLogModal(`An error occurred during backup.

${String(error)}`);
    }
  };

  const handleDeleteRequest = useCallback((backupName: string): void => {
    setBackupToDelete(backupName);
  }, []);

  const handleConfirmDelete = async (): Promise<void> => {
    if (!backupToDelete) return;
    try {
      const result = await deleteBackup.mutateAsync({
        dbType: activeTab,
        backupName: backupToDelete,
      });
      if (result.ok) {
        toast('Backup deleted successfully.', { variant: 'success' });
      } else {
        toast('Failed to delete backup.', { variant: 'error' });
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'deleteBackup',
        backupName: backupToDelete,
        dbType: activeTab,
      });
      toast('An error occurred during deletion.', { variant: 'error' });
    } finally {
      setBackupToDelete(null);
    }
  };

  const handleUpload = async (files: File[], helpers?: FileUploadHelpers): Promise<void> => {
    const file = files[0];
    if (!file) return;

    try {
      const result = await uploadBackup.mutateAsync({
        dbType: activeTab,
        file,
        onProgress: (loaded: number, total?: number) => helpers?.reportProgress(loaded, total),
      });
      if (result.ok) {
        toast('Backup uploaded successfully.', { variant: 'success' });
      } else {
        toast('Failed to upload backup.', { variant: 'error' });
      }
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'uploadBackup',
        filename: file.name,
        dbType: activeTab,
      });
      toast('An error occurred during upload.', { variant: 'error' });
    }
  };

  const handlePreview = (backupName: string): void => {
    const url = `/admin/databases/preview?backup=${encodeURIComponent(backupName)}&type=${activeTab}`;
    startTransition(() => {
      router.push(url);
    });
  };

  const handlePreviewCurrent = (): void => {
    startTransition(() => {
      router.push(`/admin/databases/preview?mode=current&type=${activeTab}`);
    });
  };

  const handleSchedulerEnabledDraftChange = useCallback((enabled: boolean): void => {
    setSchedulerEnabledDraft(enabled);
  }, []);

  const handleRepeatSchedulerTickDraftChange = useCallback((enabled: boolean): void => {
    setRepeatTickEnabledDraft(enabled);
  }, []);

  const handleActiveTargetEnabledDraftChange = useCallback((enabled: boolean): void => {
    setActiveTargetEnabledDraft(enabled);
  }, []);

  const handleActiveTargetTimeLocalChange = useCallback((value: string): void => {
    setActiveTargetTimeLocalDraft(value);
  }, []);

  const saveDailySchedule = useCallback(async (): Promise<void> => {
    if (!isValidDatabaseEngineBackupTimeUtc(activeTargetTimeLocalDraft)) {
      toast('Backup time must be a valid HH:MM value.', { variant: 'error' });
      return;
    }

    const nextTimeUtc = localHmToUtcHm(activeTargetTimeLocalDraft);
    if (!nextTimeUtc) {
      toast('Failed to convert local backup time to UTC.', { variant: 'error' });
      return;
    }

    const activeTargetNext = {
      ...activeTargetSchedule,
      enabled: activeTargetEnabledDraft,
      cadence: 'daily' as const,
      intervalDays: 1,
      timeUtc: nextTimeUtc,
    };
    const nextSchedule = {
      ...backupSchedule,
      schedulerEnabled: schedulerEnabledDraft,
      repeatTickEnabled: repeatTickEnabledDraft,
      mongodb: activeTargetNext,
    };

    try {
      await updateSetting.mutateAsync({
        key: DATABASE_ENGINE_BACKUP_SCHEDULE_KEY,
        value: JSON.stringify(nextSchedule),
      });
      await settingsQuery.refetch();
      void fetch('/api/databases/engine/backup-scheduler/status', {
        method: 'GET',
        cache: 'no-store',
      });
      toast('Backup schedule saved.', { variant: 'success' });
    } catch (error: unknown) {
      logClientCatch(error, {
        source: 'DatabaseBackupsPanel',
        action: 'saveDailySchedule',
        setting: 'database_engine_backup_schedule_v1',
        dbType: activeTargetKey,
      });
      toast('Failed to save backup schedule.', { variant: 'error' });
    }
  }, [
    activeTargetTimeLocalDraft,
    toast,
    activeTargetSchedule,
    activeTargetEnabledDraft,
    activeTargetKey,
    backupSchedule,
    schedulerEnabledDraft,
    repeatTickEnabledDraft,
    updateSetting,
    settingsQuery,
  ]);

  return {
    activeTab,
    setActiveTab,
    isLogModalOpen,
    logModalContent,
    isRestoreModalOpen,
    selectedBackupForRestore,
    backupToDelete,
    setBackupToDelete,
    setIsRestoreModalOpen,
    setSelectedBackupForRestore,
    data,
    isLoading: backupsQuery.isFetching,
    isProd,
    backupRunNowAllowed,
    backupMaintenanceAllowed,
    schedulerEnabled,
    repeatSchedulerTickEnabled,
    schedulerEnabledDraft,
    repeatTickEnabledDraft,
    activeTargetEnabledDraft,
    activeTargetTimeLocalDraft,
    activeTargetTimeLocalDraftValid,
    isBackupScheduleDirty,
    activeTargetKey,
    isBackupScheduleSaving,
    settingsValidationErrors,
    closeLogModal,
    handleBackup,
    handleUpload,
    handleRestoreRequest,
    handleRestoreConfirm,
    handleDeleteRequest,
    handleConfirmDelete,
    handlePreview,
    handlePreviewCurrent,
    handleSchedulerEnabledDraftChange,
    handleRepeatSchedulerTickDraftChange,
    handleActiveTargetEnabledDraftChange,
    handleActiveTargetTimeLocalChange,
    saveDailySchedule,
  };
}

/**
 * Database Engine State Hook
 * 
 * Comprehensive state management for database engine operations.
 * Provides:
 * - Router integration with loading states
 * - URL parameter synchronization for engine settings
 * - Engine status monitoring and job tracking
 * - Backup scheduler status management
 * - Real-time state updates with transition handling
 */

'use client';

import { useRouter } from 'nextjs-toploader/app';
import { usePathname, useSearchParams } from 'next/navigation';
import { startTransition, useState, useMemo, useCallback, useEffect, useRef } from 'react';

import type {
  DatabaseEngineStatus,
  DatabaseEngineOperationsJobs,
  DatabaseEngineBackupSchedulerStatus,
  DatabaseEngineManagedMongoApplicationTarget,
  DatabaseEngineManagedMongoDatabasesResponse,
  DatabaseEngineMongoPendingSyncRequest,
  DatabaseEngineMongoSourceState,
  DatabaseEngineMongoSyncDirection,
  RedisOverview,
  DatabaseEngineProviderPreview,
  DatabaseEngineWorkspaceView,
  UnifiedCollection,
  CollectionSchema,
} from '@/shared/contracts/database';
import { useSettingsMap, useUpdateSettingsBulk } from '@/shared/hooks/use-settings';
import { ApiError } from '@/shared/lib/api-client';
import {
  DATABASE_ENGINE_BACKUP_SCHEDULE_KEY,
  DATABASE_ENGINE_COLLECTION_ROUTE_MAP_KEY,
  DATABASE_ENGINE_OPERATION_CONTROLS_KEY,
  DATABASE_ENGINE_POLICY_KEY,
  DATABASE_ENGINE_SERVICE_ROUTE_MAP_KEY,
  DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE,
  DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS,
  DEFAULT_DATABASE_ENGINE_POLICY,
  type DatabaseEngineBackupSchedule,
  type DatabaseEngineOperationControls,
  type DatabaseEnginePolicy,
} from '@/shared/lib/db/database-engine-constants';
import { extractMutationErrorMessage } from '@/shared/lib/mutation-error-handler';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

import {
  parseDatabaseEngineBackupScheduleSetting,
  parseDatabaseEngineCollectionRouteMapSetting,
  parseDatabaseEngineOperationControlsSetting,
  parseDatabaseEnginePolicySetting,
  parseDatabaseEngineServiceRouteMapSetting,
} from './database-engine-settings-parsing';
import {
  useDatabaseBackupSchedulerStatus,
  useBackupDatabaseEngineManagedMongoMutation,
  useDatabaseEngineManagedMongoDatabases,
  useDatabaseEngineOperationsJobs,
  useDatabaseEngineMongoSource,
  useDatabaseEngineProviderPreview,
  useSyncDatabaseEngineManagedMongoMutation,
  useSyncDatabaseEngineMongoSourceMutation,
  useDatabaseEngineStatus,
  useAllCollectionsSchema,
  useRedisOverview,
} from '../hooks/useDatabaseQueries';

export interface DatabaseCollectionRow extends UnifiedCollection {
  assignedProvider: 'mongodb' | 'redis' | 'auto';
}

export interface UseDatabaseEngineStateReturn {
  engineStatus: DatabaseEngineStatus | undefined;
  backupSchedulerStatus: DatabaseEngineBackupSchedulerStatus | undefined;
  operationsJobs: DatabaseEngineOperationsJobs | undefined;
  providerPreview: DatabaseEngineProviderPreview | undefined;
  mongoSourceState: DatabaseEngineMongoSourceState | undefined;
  managedMongoDatabases: DatabaseEngineManagedMongoDatabasesResponse | undefined;
  redisOverview: RedisOverview | undefined;
  activeView: DatabaseEngineWorkspaceView;
  setActiveView: (view: DatabaseEngineWorkspaceView) => void;
  rows: DatabaseCollectionRow[];
  isLoading: boolean;
  isSaving: boolean;
  policy: DatabaseEnginePolicy;
  serviceRouteMap: Record<string, string>;
  collectionRouteMap: Record<string, string>;
  backupSchedule: DatabaseEngineBackupSchedule;
  operationControls: DatabaseEngineOperationControls;
  updatePolicy: (updates: Partial<DatabaseEnginePolicy>) => void;
  updateServiceRoute: (service: string, provider: string) => void;
  updateCollectionRoute: (collection: string, provider: string) => void;
  updateBackupSchedule: (updates: Partial<DatabaseEngineBackupSchedule>) => void;
  updateOperationControls: (updates: Partial<DatabaseEngineOperationControls>) => void;
  syncMongoSources: (
    direction: 'cloud_to_local' | 'local_to_cloud',
    application?: DatabaseEngineManagedMongoApplicationTarget
  ) => Promise<void>;
  backupManagedMongo: (application: DatabaseEngineManagedMongoApplicationTarget) => Promise<void>;
  syncManagedMongo: (
    direction: 'cloud_to_local' | 'local_to_cloud',
    application: DatabaseEngineManagedMongoApplicationTarget
  ) => Promise<void>;
  saveSettings: () => Promise<void>;
  isDirty: boolean;
  refetchAll: () => void;
  validationErrors: string[];
  isSyncingMongoSources: boolean;
  pendingMongoSourceSync: DatabaseEngineMongoPendingSyncRequest | null;
  isBackingUpManagedMongo: boolean;
  isSyncingManagedMongo: boolean;
}

const isMongoSyncTimeoutError = (error: unknown): error is Error =>
  error instanceof Error &&
  (error.message.startsWith('Request timeout after ') ||
    error.message.startsWith('Response body timeout after '));

const didMongoSyncCompleteAfterRequestStarted = (
  state: DatabaseEngineMongoSourceState | undefined,
  direction: DatabaseEngineMongoSyncDirection,
  requestStartedAtMs: number
): boolean => {
  const syncedAt = state?.lastSync?.syncedAt;
  if (syncedAt == null || syncedAt === '' || state?.lastSync?.direction !== direction) {
    return false;
  }

  const syncedAtMs = Date.parse(syncedAt);
  return Number.isFinite(syncedAtMs) && syncedAtMs >= requestStartedAtMs - 1_000;
};

const getMongoSyncInProgressMessage = (
  state: DatabaseEngineMongoSourceState | undefined
): string | null => {
  const syncInProgress = state?.syncInProgress;
  if (!syncInProgress) {
    return null;
  }

  const applicationLabel = syncInProgress.application === 'all'
    ? 'all apps'
    : syncInProgress.application;
  return `MongoDB sync is still running for ${applicationLabel}: ${syncInProgress.source} -> ${syncInProgress.target}. Started at ${syncInProgress.acquiredAt}.`;
};

export function useDatabaseEngineState(): UseDatabaseEngineStateReturn {
  const router = useRouter();
  const pathname = usePathname();
  const searchParams = useSearchParams();
  const { toast } = useToast();

  const engineStatusQuery = useDatabaseEngineStatus();
  const backupSchedulerStatusQuery = useDatabaseBackupSchedulerStatus();
  const operationsJobsQuery = useDatabaseEngineOperationsJobs(30);
  const mongoSourceQuery = useDatabaseEngineMongoSource();
  const managedMongoQuery = useDatabaseEngineManagedMongoDatabases();
  const providerPreviewQuery = useDatabaseEngineProviderPreview();
  const redisOverviewQuery = useRedisOverview();
  const schemaQuery = useAllCollectionsSchema();

  const requestedView = searchParams.get('view');
  const VALID_VIEWS = new Set<DatabaseEngineWorkspaceView>([
    'engine', 'backups', 'operations', 'redis', 'preview', 'crud',
  ]);
  const activeView: DatabaseEngineWorkspaceView =
    requestedView !== null && VALID_VIEWS.has(requestedView as DatabaseEngineWorkspaceView)
      ? (requestedView as DatabaseEngineWorkspaceView)
      : 'engine';

  const setActiveView = useCallback(
    (view: DatabaseEngineWorkspaceView) => {
      const params = new URLSearchParams(searchParams.toString());
      params.set('view', view);
      startTransition(() => {
        router.push(`${pathname}?${params.toString()}`);
      });
    },
    [pathname, router, searchParams]
  );

  const { data: settingsMap, isPending: settingsLoading } = useSettingsMap({ scope: 'all' });

  const updateSettingsBulk = useUpdateSettingsBulk();
  const backupManagedMongoMutation = useBackupDatabaseEngineManagedMongoMutation();
  const syncManagedMongoMutation = useSyncDatabaseEngineManagedMongoMutation();
  const syncMongoSourcesMutation = useSyncDatabaseEngineMongoSourceMutation();

  const [policy, setPolicy] = useState<DatabaseEnginePolicy>(DEFAULT_DATABASE_ENGINE_POLICY);
  const [serviceRouteMap, setServiceRouteMap] = useState<Record<string, string>>({});
  const [collectionRouteMap, setCollectionRouteMap] = useState<Record<string, string>>({});
  const [backupSchedule, setBackupSchedule] = useState<DatabaseEngineBackupSchedule>(
    DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE
  );
  const [operationControls, setOperationControls] = useState<DatabaseEngineOperationControls>(
    DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS
  );

  const [isDirty, setIsDirty] = useState(false);
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [pendingMongoSourceSync, setPendingMongoSourceSync] =
    useState<DatabaseEngineMongoPendingSyncRequest | null>(null);
  const lastValidationErrorSignatureRef = useRef<string | null>(null);

  const resolveMongoSyncToast = useCallback(
    async (
      error: unknown,
      direction: DatabaseEngineMongoSyncDirection,
      requestStartedAtMs: number
    ): Promise<{ message: string; variant: 'success' | 'warning' | 'error' }> => {
      if (isMongoSyncTimeoutError(error)) {
        try {
          const refreshedState = (await mongoSourceQuery.refetch()).data;
          const refreshedLastSync = refreshedState?.lastSync;

          if (didMongoSyncCompleteAfterRequestStarted(refreshedState, direction, requestStartedAtMs)) {
            return {
              message: `MongoDB sync completed: ${refreshedLastSync?.source ?? 'unknown'} -> ${refreshedLastSync?.target ?? 'unknown'}. Synced at ${refreshedLastSync?.syncedAt ?? 'unknown time'}.`,
              variant: 'success',
            };
          }

          const syncInProgressMessage = getMongoSyncInProgressMessage(refreshedState);
          if (syncInProgressMessage !== null) {
            return {
              message: `${syncInProgressMessage} The server has not reported a final result yet.`,
              variant: 'warning',
            };
          }
        } catch (refetchError) {
          logClientError(refetchError, {
            context: {
              source: 'useDatabaseEngineState',
              action: 'resolveMongoSyncToast',
              direction,
            },
          });
        }

        return {
          message:
            'MongoDB sync request timed out before the server reported a final result. Check MongoDB source status before retrying.',
          variant: 'warning',
        };
      }

      if (error instanceof ApiError && error.status === 423) {
        return {
          message: error.message,
          variant: 'warning',
        };
      }

      return {
        message: extractMutationErrorMessage(error, 'Failed to synchronize MongoDB sources.'),
        variant: 'error',
      };
    },
    [mongoSourceQuery]
  );

  const parsedPersistedSettings = useMemo(() => {
    const errors: string[] = [];
    const loggedErrors: Array<{ label: string; error: unknown }> = [];

    const parseSetting = <T>(label: string, parser: () => T, fallback: T): T => {
      try {
        return parser();
      } catch (error) {
        logClientError(error);
        const message =
          error instanceof Error ? error.message : `Invalid ${label} settings payload.`;
        errors.push(message);
        loggedErrors.push({ label, error });
        return fallback;
      }
    };

    return {
      policy: parseSetting(
        DATABASE_ENGINE_POLICY_KEY,
        () => parseDatabaseEnginePolicySetting(settingsMap?.get(DATABASE_ENGINE_POLICY_KEY)),
        DEFAULT_DATABASE_ENGINE_POLICY
      ),
      serviceRouteMap: parseSetting(
        DATABASE_ENGINE_SERVICE_ROUTE_MAP_KEY,
        () =>
          parseDatabaseEngineServiceRouteMapSetting(
            settingsMap?.get(DATABASE_ENGINE_SERVICE_ROUTE_MAP_KEY)
          ),
        {}
      ),
      collectionRouteMap: parseSetting(
        DATABASE_ENGINE_COLLECTION_ROUTE_MAP_KEY,
        () =>
          parseDatabaseEngineCollectionRouteMapSetting(
            settingsMap?.get(DATABASE_ENGINE_COLLECTION_ROUTE_MAP_KEY)
          ),
        {}
      ),
      backupSchedule: parseSetting(
        DATABASE_ENGINE_BACKUP_SCHEDULE_KEY,
        () =>
          parseDatabaseEngineBackupScheduleSetting(
            settingsMap?.get(DATABASE_ENGINE_BACKUP_SCHEDULE_KEY)
          ),
        DEFAULT_DATABASE_ENGINE_BACKUP_SCHEDULE
      ),
      operationControls: parseSetting(
        DATABASE_ENGINE_OPERATION_CONTROLS_KEY,
        () =>
          parseDatabaseEngineOperationControlsSetting(
            settingsMap?.get(DATABASE_ENGINE_OPERATION_CONTROLS_KEY)
          ),
        DEFAULT_DATABASE_ENGINE_OPERATION_CONTROLS
      ),
      errors,
      loggedErrors,
    };
  }, [settingsMap]);

  useEffect(() => {
    if (settingsMap) {
      setPolicy(parsedPersistedSettings.policy);
      setServiceRouteMap(parsedPersistedSettings.serviceRouteMap);
      setCollectionRouteMap(parsedPersistedSettings.collectionRouteMap);
      setBackupSchedule(parsedPersistedSettings.backupSchedule);
      setOperationControls(parsedPersistedSettings.operationControls);
      setValidationErrors(parsedPersistedSettings.errors);
      setIsDirty(false);
    }
  }, [parsedPersistedSettings, settingsMap]);

  useEffect(() => {
    if (parsedPersistedSettings.loggedErrors.length === 0) {
      lastValidationErrorSignatureRef.current = null;
      return;
    }

    const signature = parsedPersistedSettings.errors.join('::');
    if (lastValidationErrorSignatureRef.current === signature) return;
    lastValidationErrorSignatureRef.current = signature;

    parsedPersistedSettings.loggedErrors.forEach(
      ({ label, error }: { label: string; error: unknown }): void => {
        logClientError(error, {
          context: {
            source: 'useDatabaseEngineState',
            action: 'parsePersistedSettings',
            setting: label,
          },
        });
      }
    );
  }, [parsedPersistedSettings.errors, parsedPersistedSettings.loggedErrors]);

  const hasActiveOperationJobs =
    operationsJobsQuery.data?.jobs.some(
      (job) => job.status === 'queued' || job.status === 'running'
    ) ?? false;

  useEffect(() => {
    const shouldPollActiveJobs =
      pendingMongoSourceSync !== null ||
      mongoSourceQuery.data?.syncInProgress != null ||
      hasActiveOperationJobs;

    if (!shouldPollActiveJobs) return;

    const intervalId = window.setInterval(() => {
      void mongoSourceQuery.refetch();
      void operationsJobsQuery.refetch();
    }, 3_000);

    return () => {
      window.clearInterval(intervalId);
    };
  }, [
    hasActiveOperationJobs,
    mongoSourceQuery,
    mongoSourceQuery.data?.syncInProgress,
    operationsJobsQuery,
    pendingMongoSourceSync,
  ]);

  const rows = useMemo<DatabaseCollectionRow[]>(() => {
    const data = schemaQuery.data;
    if (!data) return [];
    return [...data.collections]
      .map((collection: CollectionSchema): DatabaseCollectionRow => {
        const configuredProvider = collectionRouteMap[collection.name];
        return {
          name: collection.name,
          existsInMongo: true,
          mongoDocumentCount: collection.documentCount ?? null,
          mongoFieldCount: collection.fields.length,
          assignedProvider:
            configuredProvider === 'mongodb' || configuredProvider === 'redis'
              ? configuredProvider
              : 'auto',
        };
      })
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [collectionRouteMap, schemaQuery.data]);

  const handleSave = async () => {
    try {
      await updateSettingsBulk.mutateAsync([
        { key: DATABASE_ENGINE_POLICY_KEY, value: JSON.stringify(policy) },
        { key: DATABASE_ENGINE_SERVICE_ROUTE_MAP_KEY, value: JSON.stringify(serviceRouteMap) },
        {
          key: DATABASE_ENGINE_COLLECTION_ROUTE_MAP_KEY,
          value: JSON.stringify(collectionRouteMap),
        },
        { key: DATABASE_ENGINE_BACKUP_SCHEDULE_KEY, value: JSON.stringify(backupSchedule) },
        { key: DATABASE_ENGINE_OPERATION_CONTROLS_KEY, value: JSON.stringify(operationControls) },
      ]);
      setIsDirty(false);
      toast('Database engine settings saved', { variant: 'success' });
    } catch (_error) {
      logClientError(_error);
      toast('Failed to save database engine settings', { variant: 'error' });
    }
  };

  return {
    engineStatus: engineStatusQuery.data,
    backupSchedulerStatus: backupSchedulerStatusQuery.data,
    operationsJobs: operationsJobsQuery.data,
    mongoSourceState: mongoSourceQuery.data,
    managedMongoDatabases: managedMongoQuery.data,
    providerPreview: providerPreviewQuery.data,
    redisOverview: redisOverviewQuery.data,
    activeView,
    setActiveView,
    rows,
    isLoading:
      engineStatusQuery.isPending ||
      backupSchedulerStatusQuery.isPending ||
      operationsJobsQuery.isPending ||
      mongoSourceQuery.isPending ||
      managedMongoQuery.isPending ||
      settingsLoading,
    isSaving: updateSettingsBulk.isPending,
    policy,
    serviceRouteMap,
    collectionRouteMap,
    backupSchedule,
    operationControls,
    updatePolicy: (updates) => {
      setPolicy((prev) => ({ ...prev, ...updates }));
      setIsDirty(true);
    },
    updateServiceRoute: (service, provider) => {
      setServiceRouteMap((prev) => {
        const next = { ...prev };
        if (provider === 'auto') {
          delete next[service];
        } else {
          next[service] = provider;
        }
        return next;
      });
      setIsDirty(true);
    },
    updateCollectionRoute: (collection, provider) => {
      setCollectionRouteMap((prev) => {
        const next = { ...prev };
        if (provider === 'auto') {
          delete next[collection];
        } else {
          next[collection] = provider;
        }
        return next;
      });
      setIsDirty(true);
    },
    updateBackupSchedule: (updates) => {
      setBackupSchedule((prev) => ({ ...prev, ...updates }));
      setIsDirty(true);
    },
    updateOperationControls: (updates) => {
      setOperationControls((prev) => ({ ...prev, ...updates }));
      setIsDirty(true);
    },
    syncMongoSources: async (direction, application = 'all') => {
      const requestStartedAtMs = Date.now();
      setPendingMongoSourceSync({
        direction,
        application,
        startedAt: new Date(requestStartedAtMs).toISOString(),
      });
      void mongoSourceQuery.refetch();
      try {
        const response = await syncMongoSourcesMutation.mutateAsync({ direction, application });
        toast(response.message, { variant: 'success' });
        mongoSourceQuery.refetch().catch(() => undefined);
      } catch (error) {
        logClientError(error);
        const nextToast = await resolveMongoSyncToast(error, direction, requestStartedAtMs);
        toast(nextToast.message, { variant: nextToast.variant });
      } finally {
        setPendingMongoSourceSync(null);
      }
    },
    backupManagedMongo: async (application) => {
      try {
        const response = await backupManagedMongoMutation.mutateAsync(application);
        const fallbackLabel = application === 'all' ? 'all managed databases' : application;
        toast(response.message ?? `Backup created for ${fallbackLabel}.`, {
          variant: 'success',
        });
        void managedMongoQuery.refetch();
      } catch (error) {
        logClientError(error);
        toast(extractMutationErrorMessage(error, 'Failed to create managed MongoDB backup.'), {
          variant: 'error',
        });
      }
    },
    syncManagedMongo: async (direction, application) => {
      const requestStartedAtMs = Date.now();
      setPendingMongoSourceSync({
        direction,
        application,
        startedAt: new Date(requestStartedAtMs).toISOString(),
      });
      void mongoSourceQuery.refetch();
      try {
        const response = await syncManagedMongoMutation.mutateAsync({ direction, application });
        toast(response.message, { variant: 'success' });
        void managedMongoQuery.refetch();
        void mongoSourceQuery.refetch();
      } catch (error) {
        logClientError(error);
        const nextToast = await resolveMongoSyncToast(error, direction, requestStartedAtMs);
        toast(nextToast.message, { variant: nextToast.variant });
      } finally {
        setPendingMongoSourceSync(null);
      }
    },
    saveSettings: handleSave,
    isDirty,
    refetchAll: () => {
      void engineStatusQuery.refetch();
      void backupSchedulerStatusQuery.refetch();
      void operationsJobsQuery.refetch();
      void mongoSourceQuery.refetch();
      void managedMongoQuery.refetch();
      void providerPreviewQuery.refetch();
      void schemaQuery.refetch();
      void redisOverviewQuery.refetch();
    },
    validationErrors,
    isSyncingMongoSources: syncMongoSourcesMutation.isPending,
    pendingMongoSourceSync,
    isBackingUpManagedMongo: backupManagedMongoMutation.isPending,
    isSyncingManagedMongo: syncManagedMongoMutation.isPending,
  };
}

import type { RefObject } from 'react';

import type {
  DatabasePreviewGroup,
  DatabaseTableDetail,
  DatabaseTablePreviewData,
} from '@/shared/contracts/database';
import { getMotionSafeScrollBehavior } from '@/shared/utils/motion-accessibility';

const DATABASE_PREVIEW_SCROLL_DELAY_MS = 50;

export const scheduleDatabasePreviewScroll = (
  sectionRef: RefObject<HTMLDivElement | null>
): void => {
  setTimeout(
    () =>
      sectionRef.current?.scrollIntoView({
        behavior: getMotionSafeScrollBehavior('smooth'),
        block: 'start',
      }),
    DATABASE_PREVIEW_SCROLL_DELAY_MS
  );
};

export const filterDatabasePreviewGroups = (
  groups: DatabasePreviewGroup[],
  groupQuery: string
): DatabasePreviewGroup[] => {
  const query = groupQuery.trim().toLowerCase();
  if (!query) {
    return groups;
  }

  return groups
    .map((group) => {
      const matchesType = group.type.toLowerCase().includes(query);
      const objects = group.objects.filter((obj) => obj.toLowerCase().includes(query));
      if (!matchesType && objects.length === 0) {
        return null;
      }

      return matchesType ? group : { ...group, objects };
    })
    .filter((group): group is DatabasePreviewGroup => Boolean(group));
};

export const filterDatabasePreviewTableDetails = (
  tableDetails: DatabaseTableDetail[],
  tableQuery: string
): DatabaseTableDetail[] => {
  const query = tableQuery.trim().toLowerCase();
  if (!query) {
    return tableDetails;
  }

  return tableDetails.filter((detail) => detail.name.toLowerCase().includes(query));
};

export const buildDatabasePreviewConsoleSql = (tableName: string): string =>
  JSON.stringify(
    {
      collection: tableName,
      operation: 'find',
      filter: {},
    },
    null,
    2
  );

export const computeDatabasePreviewStats = (
  tableDetails: DatabaseTableDetail[]
): {
  totalFks: number;
  totalIndexes: number;
} => ({
  totalFks: tableDetails.reduce((sum, detail) => sum + detail.foreignKeys.length, 0),
  totalIndexes: tableDetails.reduce((sum, detail) => sum + detail.indexes.length, 0),
});

export const computeDatabasePreviewMaxPage = (
  tableRows: DatabaseTablePreviewData[],
  pageSize: number
): number => {
  if (tableRows.length === 0) {
    return 1;
  }

  const pages = tableRows.map((table) => Math.max(1, Math.ceil(table.totalRows / pageSize)));
  return Math.max(1, ...pages);
};

'use client';

import { useState, useMemo, useCallback, useRef } from 'react';

import {
  useDatabaseConfig,
  useDatabaseData,
  useDatabasePagination,
} from '../context/DatabaseContext';
import {
  buildDatabasePreviewConsoleSql,
  computeDatabasePreviewMaxPage,
  computeDatabasePreviewStats,
  filterDatabasePreviewGroups,
  filterDatabasePreviewTableDetails,
  scheduleDatabasePreviewScroll,
} from './useDatabasePreviewState.helpers';

const useDatabasePreviewFilters = ({
  groups,
  tableDetails,
}: Pick<ReturnType<typeof useDatabaseData>, 'groups' | 'tableDetails'>) => {
  const [groupQuery, setGroupQuery] = useState('');
  const [tableQuery, setTableQuery] = useState('');
  const [expandedGroups, setExpandedGroups] = useState<Record<string, boolean>>({});

  const filteredGroups = useMemo(
    () => filterDatabasePreviewGroups(groups, groupQuery),
    [groupQuery, groups]
  );
  const filteredTableDetails = useMemo(
    () => filterDatabasePreviewTableDetails(tableDetails, tableQuery),
    [tableDetails, tableQuery]
  );
  const toggleGroup = useCallback((type: string) => {
    setExpandedGroups((prev) => ({ ...prev, [type]: !prev[type] }));
  }, []);

  return {
    expandedGroups,
    filteredGroups,
    filteredTableDetails,
    groupQuery,
    setGroupQuery,
    setTableQuery,
    tableQuery,
    toggleGroup,
  };
};

const useDatabasePreviewConsole = () => {
  const [consoleSql, setConsoleSql] = useState('');
  const [showConsole, setShowConsole] = useState(false);
  const consoleSectionRef = useRef<HTMLDivElement>(null);

  const handleQueryTable = useCallback((tableName: string) => {
    setConsoleSql(buildDatabasePreviewConsoleSql(tableName));
    setShowConsole(true);
    scheduleDatabasePreviewScroll(consoleSectionRef);
  }, []);

  return {
    consoleSectionRef,
    consoleSql,
    handleQueryTable,
    setConsoleSql,
    setShowConsole,
    showConsole,
  };
};

const useDatabasePreviewCrud = () => {
  const [crudTable, setCrudTable] = useState('');
  const [showCrud, setShowCrud] = useState(false);
  const crudSectionRef = useRef<HTMLDivElement>(null);

  const handleManageTable = useCallback((tableName: string) => {
    setCrudTable(tableName);
    setShowCrud(true);
    scheduleDatabasePreviewScroll(crudSectionRef);
  }, []);

  return {
    crudSectionRef,
    crudTable,
    handleManageTable,
    setCrudTable,
    setShowCrud,
    showCrud,
  };
};

const useDatabasePreviewDerived = ({
  pageSize,
  tableDetails,
  tableRows,
}: {
  pageSize: number;
  tableDetails: ReturnType<typeof useDatabaseData>['tableDetails'];
  tableRows: ReturnType<typeof useDatabaseData>['tableRows'];
}) => {
  const stats = useMemo(() => computeDatabasePreviewStats(tableDetails), [tableDetails]);
  const maxPage = useMemo(
    () => computeDatabasePreviewMaxPage(tableRows, pageSize),
    [pageSize, tableRows]
  );

  return {
    maxPage,
    stats,
  };
};

export function useDatabasePreviewState() {
  const { dbType, mode, backupName } = useDatabaseConfig();
  const { tableDetails, groups, tables, tableRows, enums, databaseSize, isLoading, error } =
    useDatabaseData();
  const { page, setPage, pageSize, setPageSize } = useDatabasePagination();
  const filters = useDatabasePreviewFilters({ groups, tableDetails });
  const consoleState = useDatabasePreviewConsole();
  const crudState = useDatabasePreviewCrud();
  const derived = useDatabasePreviewDerived({
    pageSize,
    tableDetails,
    tableRows,
  });

  return {
    backupName,
    consoleSectionRef: consoleState.consoleSectionRef,
    consoleSql: consoleState.consoleSql,
    crudSectionRef: crudState.crudSectionRef,
    crudTable: crudState.crudTable,
    dbType,
    databaseSize,
    error,
    enums,
    expandedGroups: filters.expandedGroups,
    filteredGroups: filters.filteredGroups,
    filteredTableDetails: filters.filteredTableDetails,
    groupQuery: filters.groupQuery,
    groups,
    handleManageTable: crudState.handleManageTable,
    handleQueryTable: consoleState.handleQueryTable,
    isLoading,
    maxPage: derived.maxPage,
    mode,
    page,
    pageSize,
    setConsoleSql: consoleState.setConsoleSql,
    setCrudTable: crudState.setCrudTable,
    setGroupQuery: filters.setGroupQuery,
    setPage,
    setPageSize,
    setShowConsole: consoleState.setShowConsole,
    setShowCrud: crudState.setShowCrud,
    setTableQuery: filters.setTableQuery,
    showConsole: consoleState.showConsole,
    showCrud: crudState.showCrud,
    stats: derived.stats,
    tableDetails,
    tableQuery: filters.tableQuery,
    tableRows,
    tables,
    toggleGroup: filters.toggleGroup,
  };
}

