import { useEffect, useMemo, useState } from 'react';
import { useSettingsMap, useUpdateSetting } from '@/shared/hooks/use-settings';
import { useToast } from '@/shared/ui/primitives.public';
import { logClientCatch } from '@/shared/utils/observability/client-error-logger';

const APP_DB_PROVIDER_SETTING_KEY = 'app_db_provider';

export function useDatabaseEngineController() {
  const settingsQuery = useSettingsMap({ scope: 'all' });
  const updateSetting = useUpdateSetting();
  const { toast } = useToast();
  const persistedProvider = settingsQuery.data?.get(APP_DB_PROVIDER_SETTING_KEY) === 'redis' ? 'redis' : 'mongodb';
  const [provider, setProvider] = useState<'mongodb' | 'redis'>(persistedProvider);
  const [isSaving, setIsSaving] = useState(false);
  const policy = useMemo(() => ({ provider }), [provider]);

  useEffect(() => {
    setProvider(persistedProvider);
  }, [persistedProvider]);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await updateSetting.mutateAsync({ key: APP_DB_PROVIDER_SETTING_KEY, value: provider });
      toast('Engine provider updated', { variant: 'success' });
      await settingsQuery.refetch();
    } catch (e) {
      logClientCatch(e, { source: 'DatabaseEnginePage', action: 'updateProvider' });
      toast('Failed to update provider', { variant: 'error' });
    } finally {
      setIsSaving(false);
    }
  };

  return { policy, isLoading: settingsQuery.isPending, provider, setProvider, handleSave, isSaving };
}

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import {
  enqueueProductAiJob,
  enqueueProductAiJobToQueue,
  processProductAiJob,
  startProductAiJobQueue,
} from '@/features/database/server/jobs';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError, forbiddenError } from '@/shared/errors/app-error';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { assertDatabaseEngineOperationEnabled } from '@/shared/lib/db/services/database-engine-operation-guards';
import { logSystemError } from '@/shared/lib/observability/system-logger';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


const backupTypeSchema = z.enum(['mongodb']);
const isProductionRuntime = (): boolean => process.env['NODE_ENV'] === 'production';

export async function postHandler(req: NextRequest, ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();

  if (isProductionRuntime()) {
    throw forbiddenError('Database backups are disabled in production.');
  }

  await assertDatabaseEngineOperationEnabled('allowManualBackupRunNow');
  const body = ctx.body ?? null;
  z.unknown().parse(body);

  const { searchParams } = new URL(req.url);
  const parsedType = backupTypeSchema.safeParse(searchParams.get('type') ?? 'mongodb');
  if (!parsedType.success) {
    throw badRequestError('Invalid database backup type.', {
      type: searchParams.get('type'),
    });
  }

  const dbType = parsedType.data;
  const job = await enqueueProductAiJob('system', 'db_backup', {
    dbType,
    entityType: 'system',
    source: 'db_backup',
  });

  let processedInline = false;
  startProductAiJobQueue();
  try {
    const runtimeType = job.jobType ?? job.type ?? 'db_backup';
    await enqueueProductAiJobToQueue(job.id, job.productId, runtimeType, job.payload);
  } catch (enqueueError: unknown) {
    void ErrorSystem.captureException(enqueueError);
    await logSystemError({
      message:
        '[databases.backup] Failed to enqueue db backup job to runtime queue, falling back to inline processing',
      error: enqueueError,
      source: 'api/databases/backup',
      context: { jobId: job.id, dbType },
    });

    await processProductAiJob(job.id);
    processedInline = true;
  }

  return NextResponse.json({
    success: true,
    jobId: job.id,
    message: processedInline
      ? `Database backup executed inline for ${dbType}.`
      : `Database backup job queued for ${dbType}.`,
  });
}

import { promises as fs } from 'fs';
import { join } from 'path';

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import {
  mongoBackupsDir,
  ensureMongoBackupsDir,
} from '@/features/database/server';
import type { DatabaseBackupFile as DatabaseInfo } from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { normalizeOptionalQueryString } from '@/shared/lib/api/query-schema';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


const isValidDate = (value: unknown): value is Date =>
  value instanceof Date && Number.isFinite(value.getTime());

export const querySchema = z.object({
  type: z.preprocess(
    (value: unknown) => normalizeOptionalQueryString(value),
    z.enum(['mongodb']).optional()
  ),
});

async function getBackups(): Promise<DatabaseInfo[]> {
  await ensureMongoBackupsDir();

  const collectBackupFiles = async (relativeDir = ''): Promise<string[]> => {
    const dirPath = join(mongoBackupsDir, relativeDir);
    const entries = await fs.readdir(dirPath, { withFileTypes: true });
    const nested = await Promise.all(
      entries.map(async (entry) => {
        const relativePath = join(relativeDir, entry.name);
        if (entry.isDirectory()) {
          return collectBackupFiles(relativePath);
        }
        return entry.isFile() && entry.name.endsWith('.archive') ? [relativePath] : [];
      })
    );
    return nested.flat();
  };
  const backupFiles = await collectBackupFiles();

  const backups: DatabaseInfo[] = await Promise.all(
    backupFiles.map(async (file) => {
      const filePath = join(mongoBackupsDir, file);
      const stats = await fs.stat(filePath);
      const createdAt =
        isValidDate(stats.birthtime) && stats.birthtime.getTime() > 0
          ? stats.birthtime
          : isValidDate(stats.ctime)
            ? stats.ctime
            : isValidDate(stats.mtime)
              ? stats.mtime
              : new Date();
      const lastModifiedAt = isValidDate(stats.mtime) ? stats.mtime : createdAt;
      return {
        name: file,
        size: stats.size,
        createdAt: createdAt.toISOString(),
        lastModifiedAt: lastModifiedAt.toISOString(),
      };
    })
  );

  return backups.sort((a, b) => {
    const aTs = Date.parse(a.lastModifiedAt ?? a.createdAt);
    const bTs = Date.parse(b.lastModifiedAt ?? b.createdAt);
    const safeA = Number.isFinite(aTs) ? aTs : 0;
    const safeB = Number.isFinite(bTs) ? bTs : 0;
    return safeB - safeA;
  });
}

export async function getHandler(_req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();

  try {
    const backups = await getBackups();
    return NextResponse.json(backups, {
      headers: {
        'Cache-Control': 'no-store',
      },
    });
  } catch (error) {
    void ErrorSystem.captureException(error);
    const { ErrorSystem: SystemLogger } = await import('@/shared/lib/observability/system-logger');
    void SystemLogger.captureException(error, {
      service: 'api/databases/backups',
      type: 'mongodb',
    });
    throw error;
  }
}

import { ObjectId } from 'mongodb';
import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import type {
  DatabaseBrowseParams as BrowseParams,
  DatabaseBrowse as BrowseResponse,
} from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError } from '@/shared/errors/app-error';
import {
  optionalIntegerQuerySchema,
  optionalTrimmedQueryString,
} from '@/shared/lib/api/query-schema';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { assertDatabaseEngineManageAccessOrAiPathsInternal } from '@/features/database/server';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


export const querySchema = z.object({
  collection: optionalTrimmedQueryString(),
  limit: optionalIntegerQuerySchema(z.number().int().min(1)).default(20),
  skip: optionalIntegerQuerySchema(z.number().int().min(0)).default(0),
  query: optionalTrimmedQueryString(),
  provider: optionalTrimmedQueryString(),
});

async function browseMongoCollection(params: BrowseParams): Promise<BrowseResponse> {
  const db = await getMongoDb();
  const { collection, limit = 20, skip = 0, query } = params;

  const coll = db.collection(collection);

  // Parse query filter if provided
  let filter: Record<string, unknown> = {};
  if (query) {
    try {
      filter = JSON.parse(query) as Record<string, unknown>;
    } catch (error) {
      void ErrorSystem.captureException(error);
      // If not valid JSON, try text search on common fields
      filter = {
        $or: [
          { name: { $regex: query, $options: 'i' } },
          { title: { $regex: query, $options: 'i' } },
          { _id: query },
        ],
      };
    }
  }

  const [documents, total] = await Promise.all([
    coll.find(filter).skip(skip).limit(limit).toArray(),
    coll.countDocuments(filter),
  ]);

  // Convert ObjectId and Date to strings for JSON serialization
  const serializedDocs = (documents as Record<string, unknown>[]).map(
    (doc: Record<string, unknown>) => {
      const serialized: Record<string, unknown> = {};
      for (const [key, value] of Object.entries(doc)) {
        if (value instanceof ObjectId) {
          serialized[key] = value.toString();
        } else if (value instanceof Date) {
          serialized[key] = value.toISOString();
        } else if (Array.isArray(value)) {
          serialized[key] = (value as unknown[]).map((item: unknown) => {
            if (item instanceof ObjectId) {
              return item.toString();
            }
            return item;
          });
        } else {
          serialized[key] = value;
        }
      }
      return serialized;
    }
  );

  return {
    provider: 'mongodb',
    collection,
    documents: serializedDocs,
    total,
    limit,
    skip,
  };
}

export async function getHandler(
  request: NextRequest,
  _ctx: ApiHandlerContext
): Promise<Response> {
  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const collection = query.collection ?? null;
  const providerParam = query.provider?.toLowerCase() ?? '';

  if (!collection) {
    throw badRequestError('Collection parameter is required');
  }

  await assertDatabaseEngineManageAccessOrAiPathsInternal(request, { collection });

  if (providerParam && providerParam !== 'mongodb' && providerParam !== 'auto') {
    throw badRequestError('Only MongoDB browsing is supported.');
  }

  const params: BrowseParams = { collection, limit: query.limit, skip: query.skip };
  if (query.query !== undefined) {
    params.query = query.query;
  }

  const result = await browseMongoCollection(params);
  return NextResponse.json(result, {
    headers: {
      'Cache-Control': 'no-store',
    },
  });
}

import { ObjectId } from 'mongodb';
import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import {
  databaseEngineManagedMongoApplicationSchema,
  mongoSourceSchema,
} from '@/shared/contracts/database';
import { badRequestError, forbiddenError } from '@/shared/errors/app-error';
import { parseJsonBody } from '@/shared/lib/api/parse-json';
import { getMongoClient } from '@/shared/lib/db/mongo-client';
import { createManagedMongoClient } from '@/shared/lib/db/services/managed-mongo-databases';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


const MONGO_COLLECTION_NAME_MAX_LENGTH = 255;
const isValidMongoCollectionName = (value: string): boolean => {
  if (value.length === 0 || value.length > MONGO_COLLECTION_NAME_MAX_LENGTH) return false;
  if (value.includes('\0') || value.includes('$')) return false;
  return !value.startsWith('system.');
};
const collectionNameSchema = z
  .string()
  .trim()
  .min(1, 'Collection name is required.')
  .max(MONGO_COLLECTION_NAME_MAX_LENGTH, 'Collection name is too long.')
  .refine(isValidMongoCollectionName, 'Valid MongoDB collection name is required.');
const nonEmptyRecordSchema = z.record(z.string(), z.unknown()).refine(
  (value) => Object.keys(value).length > 0,
  'Object cannot be empty.'
);
const databaseCrudRequestSchema = z.union([
  z.object({
    table: collectionNameSchema,
    operation: z.literal('insert'),
    type: z.enum(['mongodb', 'auto']).optional().default('auto'),
    application: databaseEngineManagedMongoApplicationSchema.optional(),
    source: mongoSourceSchema.optional(),
    data: nonEmptyRecordSchema,
    primaryKey: z.record(z.string(), z.unknown()).optional(),
  }),
  z.object({
    table: collectionNameSchema,
    operation: z.literal('update'),
    type: z.enum(['mongodb', 'auto']).optional().default('auto'),
    application: databaseEngineManagedMongoApplicationSchema.optional(),
    source: mongoSourceSchema.optional(),
    data: nonEmptyRecordSchema,
    primaryKey: nonEmptyRecordSchema,
  }),
  z.object({
    table: collectionNameSchema,
    operation: z.literal('delete'),
    type: z.enum(['mongodb', 'auto']).optional().default('auto'),
    application: databaseEngineManagedMongoApplicationSchema.optional(),
    source: mongoSourceSchema.optional(),
    data: z.record(z.string(), z.unknown()).optional(),
    primaryKey: nonEmptyRecordSchema,
  }),
]);

export async function postHandler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();
  if (process.env['NODE_ENV'] === 'production') {
    throw forbiddenError('Database operations are disabled in production.');
  }

  const parsedBody = await parseJsonBody(req, databaseCrudRequestSchema, {
    logPrefix: 'database-engine-web.databases.crud',
  });
  if (!parsedBody.ok) {
    return parsedBody.response;
  }

  const parsed = parsedBody.data;
  const { table, operation, data, primaryKey, application, source } = parsed;
  return handleMongoCrud(table, operation, data, primaryKey, application, source);
}

function toObjectId(value: unknown): ObjectId | unknown {
  if (typeof value === 'string' && /^[a-f0-9]{24}$/i.test(value)) {
    try {
      return new ObjectId(value);
    } catch (error) {
      void ErrorSystem.captureException(error);
      return value;
    }
  }
  return value;
}

const isRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === 'object' && value !== null && !Array.isArray(value);

const toDate = (value: unknown): Date | unknown => {
  if (typeof value !== 'string') return value;
  const timestamp = Date.parse(value);
  return Number.isNaN(timestamp) ? value : new Date(timestamp);
};

const normalizeMongoCrudValue = (value: unknown): unknown => {
  if (Array.isArray(value)) {
    return value.map(normalizeMongoCrudValue);
  }
  if (!isRecord(value)) {
    return value;
  }

  const entries = Object.entries(value);
  if (entries.length === 1 && typeof value['$oid'] === 'string') {
    return toObjectId(value['$oid']);
  }
  if (entries.length === 1 && typeof value['$date'] === 'string') {
    return toDate(value['$date']);
  }

  return Object.fromEntries(
    entries.map(([key, nestedValue]) => [key, normalizeMongoCrudValue(nestedValue)])
  );
};

const normalizeMongoCrudDocument = (
  data: Record<string, unknown>
): Record<string, unknown> =>
  Object.fromEntries(
    Object.entries(data).map(([key, value]) => [key, normalizeMongoCrudValue(value)])
  );

const buildPrimaryKeyFilter = (primaryKey: Record<string, unknown>): Record<string, unknown> => {
  const filter: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(primaryKey)) {
    filter[key] = key === '_id' ? toObjectId(value) : normalizeMongoCrudValue(value);
  }
  return filter;
};

const stripImmutableMongoFields = (
  data: Record<string, unknown>,
  primaryKey: Record<string, unknown>
): Record<string, unknown> => {
  const sanitized = { ...data };
  delete sanitized['_id'];
  for (const key of Object.keys(primaryKey)) {
    delete sanitized[key];
  }
  return sanitized;
};

async function handleMongoCrud(
  collectionName: string,
  operation: 'insert' | 'update' | 'delete',
  data?: Record<string, unknown>,
  primaryKey?: Record<string, unknown>,
  application?: z.infer<typeof databaseEngineManagedMongoApplicationSchema>,
  source?: z.infer<typeof mongoSourceSchema>
): Promise<Response> {
  const managedMongo = application
    ? await createManagedMongoClient(application, source ?? 'local')
    : null;
  const mongoClient = managedMongo?.client ?? (await getMongoClient());
  const dbName = managedMongo?.dbName ?? process.env['MONGODB_DB'] ?? 'stardb';
  const db = managedMongo?.db ?? mongoClient.db(dbName);
  const collection = db.collection(collectionName);

  try {
    if (operation === 'insert') {
      if (!data || Object.keys(data).length === 0) {
        throw badRequestError('Data is required for insert.');
      }
      const insertData = normalizeMongoCrudDocument(data);
      const result = await collection.insertOne(insertData);
      return NextResponse.json({
        success: result.acknowledged,
        rowCount: result.acknowledged ? 1 : 0,
        returning: [{ _id: result.insertedId, ...insertData }],
      });
    }

    if (operation === 'update') {
      if (!data || Object.keys(data).length === 0) {
        throw badRequestError('Data is required for update.');
      }
      if (!primaryKey || Object.keys(primaryKey).length === 0) {
        throw badRequestError('Primary key is required for update.');
      }
      const updateData = stripImmutableMongoFields(data, primaryKey);
      if (Object.keys(updateData).length === 0) {
        throw badRequestError('At least one non-primary-key field is required for update.');
      }
      const result = await collection.updateOne(buildPrimaryKeyFilter(primaryKey), {
        $set: normalizeMongoCrudDocument(updateData),
      });
      return NextResponse.json({
        success: result.acknowledged,
        rowCount: result.modifiedCount,
      });
    }

    if (!primaryKey || Object.keys(primaryKey).length === 0) {
      throw badRequestError('Primary key is required for delete.');
    }
    const result = await collection.deleteOne(buildPrimaryKeyFilter(primaryKey));
    return NextResponse.json({
      success: result.acknowledged,
      rowCount: result.deletedCount,
    });
  } finally {
    if (managedMongo !== null) {
      await managedMongo.client.close().catch(() => undefined);
    }
  }
}

import { type NextRequest, NextResponse } from 'next/server';

import {
  enqueueProductAiJob,
  enqueueProductAiJobToQueue,
  processProductAiJob,
  startProductAiJobQueue,
} from '@/features/database/server/jobs';
import {
  databaseEngineBackupRunNowRequestSchema as runNowSchema,
  type DatabaseEngineBackupRunNowRequest,
} from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError, forbiddenError } from '@/shared/errors/app-error';
import { parseJsonBody } from '@/shared/lib/api/parse-json';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { markDatabaseBackupJobQueued } from '@/shared/lib/db/services/database-backup-scheduler';
import { assertDatabaseEngineOperationEnabled } from '@/shared/lib/db/services/database-engine-operation-guards';
import { logSystemError } from '@/shared/lib/observability/system-logger';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


const resolveTargets = (
  dbType: DatabaseEngineBackupRunNowRequest['dbType']
): Array<'mongodb'> => {
  return dbType === 'all' || dbType === 'mongodb' ? ['mongodb'] : [];
};

const isProductionRuntime = (): boolean => process.env['NODE_ENV'] === 'production';

export async function postHandler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();

  if (isProductionRuntime()) {
    throw forbiddenError('Database backups are disabled in production.');
  }

  await assertDatabaseEngineOperationEnabled('allowManualBackupRunNow');

  const parsed = await parseJsonBody(req, runNowSchema, {
    logPrefix: 'database-engine-web.databases.engine.backup-scheduler.run-now.POST',
  });
  if (!parsed.ok) {
    return parsed.response;
  }

  const targets = resolveTargets(parsed.data.dbType);
  if (targets.length === 0) {
    throw badRequestError('No database targets selected for backup.');
  }

  const queued: Array<{ dbType: 'mongodb'; jobId: string }> = [];
  const inlineProcessed: Array<{ dbType: 'mongodb'; jobId: string }> = [];
  startProductAiJobQueue();

  for (const dbType of targets) {
    const job = await enqueueProductAiJob('system', 'db_backup', {
      dbType,
      entityType: 'system',
      source: 'database_engine_manual_backup',
    });
    queued.push({ dbType, jobId: job.id });

    try {
      await markDatabaseBackupJobQueued(dbType, job.id);
    } catch (error) {
      void ErrorSystem.captureException(error);

      // Keep manual queue action resilient even if schedule metadata update fails.
    }

    try {
      const runtimeType = job.jobType ?? job.type ?? 'db_backup';
      await enqueueProductAiJobToQueue(job.id, job.productId, runtimeType, job.payload);
    } catch (enqueueError: unknown) {
      void ErrorSystem.captureException(enqueueError);
      await logSystemError({
        message:
          '[databases.engine.backup-scheduler.run-now] Failed to enqueue db backup job to runtime queue, falling back to inline processing',
        error: enqueueError,
        source: 'api/databases/engine/backup-scheduler/run-now',
        context: { jobId: job.id, dbType },
      });

      await processProductAiJob(job.id);
      inlineProcessed.push({ dbType, jobId: job.id });
    }
  }

  return NextResponse.json(
    {
      success: true,
      queued,
      inlineProcessed,
    },
    {
      headers: { 'Cache-Control': 'no-store' },
    }
  );
}

